fn assert_parse_error(source: &str) {
    match run_source(source) {
        Err(message) if message.starts_with("parse error:") => {}
        other => panic!("expected parse error, got {other:?}\nsource:\n{source}"),
    }
}

fn assert_parse_error_diagnostic(
    source: &str,
    expected_message: &str,
    expected_line: usize,
    expected_column: usize,
    expected_end_line: usize,
    expected_end_column: usize,
) {
    let diagnostic = source_parse_error_diagnostic(source)
        .expect(source)
        .unwrap_or_else(|| panic!("expected parse error:\n{source}"));
    assert_eq!(diagnostic.message, expected_message);
    assert_eq!(diagnostic.line, expected_line);
    assert_eq!(diagnostic.column, expected_column);
    assert_eq!(diagnostic.end_line, expected_end_line);
    assert_eq!(diagnostic.end_column, expected_end_column);
}

