fn assert_warning_diagnostic(
    source: &str,
    expected_message: &str,
    expected_line: usize,
    expected_column: usize,
    expected_end_line: usize,
    expected_end_column: usize,
) {
    let diagnostics = source_warning_diagnostics(source).expect(source);
    assert_eq!(diagnostics.len(), 1, "source:\n{source}");
    assert_eq!(diagnostics[0].category, LexWarningCategory::SyntaxWarning);
    assert_eq!(diagnostics[0].message, expected_message);
    assert_eq!(diagnostics[0].line, expected_line);
    assert_eq!(diagnostics[0].column, expected_column);
    assert_eq!(diagnostics[0].end_line, expected_end_line);
    assert_eq!(diagnostics[0].end_column, expected_end_column);
}

