// Adapted from CPython `Lib/test/test_ast/test_ast.py::AST_Tests.test_repr`
// over the current `snippets.py::eval_tests` expression inventory.
#[test]
fn cpython_ast_repr_eval_expression_snapshot_subset() {
    const EXEC_REPR_SNAPSHOT_LINES: usize = 136;
    let sources = [
        "None",
        "True",
        "False",
        "a and b",
        "a or b",
        "a + b",
        "a - b",
        "a * b",
        "a / b",
        "a @ b",
        "a // b",
        "a ** b",
        "a % b",
        "a >> b",
        "a << b",
        "a ^ b",
        "a | b",
        "a & b",
        "not v",
        "+v",
        "-v",
        "~v",
        "lambda:None",
        "{ 1:2 }",
        "{}",
        "{None,}",
        "{\n      1\n        :\n          2\n     }",
        "[\n      1\n       ,\n        1\n     ]",
        "(\n      1\n       ,\n     )",
        "{\n      1\n       ,\n        1\n     }",
        "[a for b in c if d]",
        "(a for b in c if d)",
        "{a for b in c if d}",
        "{k: v for k, v in c if d}",
        "[(a,b) for a,b in c]",
        "[(a,b) for (a,b) in c]",
        "[(a,b) for [a,b] in c]",
        "{(a,b) for a,b in c}",
        "{(a,b) for (a,b) in c}",
        "{(a,b) for [a,b] in c}",
        "((a,b) for a,b in c)",
        "((a,b) for (a,b) in c)",
        "((a,b) for [a,b] in c)",
        "1 < 2 < 3",
        "a == b",
        "a <= b",
        "a >= b",
        "a != b",
        "a is b",
        "a is not b",
        "a in b",
        "a not in b",
        "f()",
        "f(1,2,c=3,*d,**e)",
        "f(*[0, 1])",
        "f(a for a in b)",
        "10",
        "1j",
        "'string'",
        "a.b",
        "a[b:c]",
        "v",
        "[1,2,3]",
        "[]",
        "1,2,3",
        "(1,2,3)",
        "()",
        "a.b.c.d(a.b[1:2])",
        "[5][1:]",
        "[5][:1]",
        "[5][::1]",
        "[5][1:1:1]",
        "foo() if x else bar()",
        "f'{a}'",
        "f'{a:.2f}'",
        "f'{a!r}'",
        "f'foo({a})'",
        "t'{a}'",
        "t'{a:.2f}'",
        "t'{a!r}'",
        "t'{a!r:.2f}'",
        "t'foo({a})'",
    ];
    let snapshot_path =
        std::path::Path::new("/Volumes/samsung/GitHub/cpython/Lib/test/test_ast/data/ast_repr.txt");
    let snapshots = std::fs::read_to_string(snapshot_path)
        .unwrap_or_else(|error| panic!("failed to read {}: {error}", snapshot_path.display()));
    let expected = snapshots
        .lines()
        .skip(EXEC_REPR_SNAPSHOT_LINES)
        .take(sources.len())
        .map(str::to_string)
        .collect::<Vec<_>>();
    assert_eq!(expected.len(), sources.len());

    let mut program = String::from("import ast\nfor source in [\n");
    for source in sources {
        program.push_str("    ");
        program.push_str(&format!("{source:?}"));
        program.push_str(",\n");
    }
    program.push_str("]:\n    print(repr(ast.parse(source)))");

    assert_eq!(run_source(&program), Ok(expected), "source:\n{program}");
}

