fn cpython_ast_lazy_import_fields_subset() {
    assert_output(
        r#"import ast
node = ast.parse("import _ast as ast; from module import sub")
print(ast.dump(node) == "Module(body=[Import(names=[alias(name='_ast', asname='ast')], is_lazy=0), ImportFrom(module='module', names=[alias(name='sub')], level=0, is_lazy=0)])")
print(node.body[0]._fields)
print(node.body[1]._fields)
print(node.body[0].is_lazy, node.body[1].is_lazy)
lazy = ast.parse("lazy import sys as system\nlazy from math import sqrt")
print(ast.dump(lazy) == "Module(body=[Import(names=[alias(name='sys', asname='system')], is_lazy=1), ImportFrom(module='math', names=[alias(name='sqrt')], level=0, is_lazy=1)])")
print(lazy.body[0].is_lazy, lazy.body[1].is_lazy)
manual = ast.Import(names=[ast.alias("os")])
manual_from = ast.ImportFrom(module="sys", names=[ast.alias("path")], level=0)
print(manual.is_lazy, manual_from.is_lazy)
print(ast.dump(manual))
print(ast.dump(manual_from))
tree = ast.Module(body=[ast.Import([ast.alias("math")], 1)], type_ignores=[])
ns = {}
exec(compile(tree, "<ast>", "exec"), ns)
print(ns["math"].__name__)"#,
        &[
            "True",
            "('names', 'is_lazy')",
            "('module', 'names', 'level', 'is_lazy')",
            "0 0",
            "True",
            "1 1",
            "0 0",
            "Import(names=[alias(name='os')], is_lazy=0)",
            "ImportFrom(module='sys', names=[alias(name='path')], level=0, is_lazy=0)",
            "math",
        ],
    );
}

