// Adapted from CPython Lib/test/test_ast/test_ast.py::ASTOptimizationTests::
// test_folding_format. With optimization enabled, CPython folds this old-style
// `%s` format expression into the equivalent f-string AST shape.
#[test]
fn cpython_ast_optimization_format_folding_subset() {
    assert_output(
        "import ast\ncode = \"'%s' % (a,)\"\nnon = ast.parse(code, optimize=-1)\nopt = ast.parse(code, optimize=1)\nprint(type(non.body[0].value).__name__)\nprint(type(opt.body[0].value).__name__)\nprint(ast.compare(non, opt))\npart = opt.body[0].value.values[0]\nprint(type(part).__name__, part.conversion, part.value.id, part.format_spec is None)\nprint('BinOp' in ast.dump(non), 'JoinedStr' in ast.dump(opt), 'FormattedValue' in ast.dump(opt))",
        &[
            "BinOp",
            "JoinedStr",
            "False",
            "FormattedValue 115 a True",
            "True True True",
        ],
    );
}

// Adapted from CPython Lib/test/test_ast/test_ast.py::ASTOptimizationTests::
// test_folding_match_case_allowed_expressions and
// test_match_case_not_folded_in_unoptimized_ast. Match literal patterns keep
// their expression shape at optimize=0, but optimize > 0 folds signed numbers
// and real-plus-imaginary forms to Constant nodes.
#[test]
fn cpython_ast_optimization_match_case_folding_subset() {
    fn assert_match_folded(match_expr: &str, constant_count: usize, fragments: &[&str]) {
        let source = format!("match 0:\n\tcase {match_expr}: pass");
        let fragment_checks = fragments
            .iter()
            .map(|fragment| format!("print({fragment:?} in dump)\n"))
            .collect::<String>();
        let mut expected = vec!["False False".to_string(), constant_count.to_string()];
        expected.extend(fragments.iter().map(|_| "True".to_string()));
        let expected = expected.iter().map(String::as_str).collect::<Vec<_>>();
        assert_output(
            &format!(
                "import ast\nsrc = {source:?}\ndump = ast.dump(ast.parse(src, optimize=1).body[0].cases[0].pattern)\nprint('UnaryOp' in dump, 'BinOp' in dump)\nprint(dump.count('Constant(value='))\n{fragment_checks}"
            ),
            &expected,
        );
    }

    for (match_expr, fragment) in [
        ("-0", "Constant(value=0)"),
        ("-0.1", "Constant(value=-0.1)"),
        ("-0j", "Constant(value=0j)"),
        ("-0.1j", "Constant(value=-0.1j)"),
        ("1 + 2j", "Constant(value=(1+2j))"),
        ("1 - 2j", "Constant(value=(1-2j))"),
        ("1.1 + 2.1j", "Constant(value=(1.1+2.1j))"),
        ("1.1 - 2.1j", "Constant(value=(1.1-2.1j))"),
        ("-0 + 1j", "Constant(value=1j)"),
        ("-0 - 1j", "Constant(value=-1j)"),
        ("-0.1 + 1.1j", "Constant(value=(-0.1+1.1j))"),
        ("-0.1 - 1.1j", "Constant(value=(-0.1-1.1j))"),
        ("{-0: 0}", "Constant(value=0)"),
        ("{-0.1: 0}", "Constant(value=-0.1)"),
        ("{-0j: 0}", "Constant(value=0j)"),
        ("{-0.1j: 0}", "Constant(value=-0.1j)"),
        ("{1 + 2j: 0}", "Constant(value=(1+2j))"),
        ("{1 - 2j: 0}", "Constant(value=(1-2j))"),
        ("{1.1 + 2.1j: 0}", "Constant(value=(1.1+2.1j))"),
        ("{1.1 - 2.1j: 0}", "Constant(value=(1.1-2.1j))"),
        ("{-0 + 1j: 0}", "Constant(value=1j)"),
        ("{-0 - 1j: 0}", "Constant(value=-1j)"),
        ("{-0.1 + 1.1j: 0}", "Constant(value=(-0.1+1.1j))"),
        ("{-0.1 - 1.1j: 0}", "Constant(value=(-0.1-1.1j))"),
    ] {
        let constant_count = if match_expr.starts_with('{') { 2 } else { 1 };
        assert_match_folded(match_expr, constant_count, &[fragment]);
    }

    assert_match_folded(
        "{-0: 0, 0 + 1j: 0, 0.1 + 1j: 0}",
        6,
        &[
            "Constant(value=0)",
            "Constant(value=1j)",
            "Constant(value=(0.1+1j))",
        ],
    );
    for match_expr in [
        "[-0, -0.1, -0j, -0.1j]",
        "[[[[-0, -0.1, -0j, -0.1j]]]]",
        "[[-0, -0.1], -0j, -0.1j]",
        "[[-0, -0.1], [-0j, -0.1j]]",
        "(-0, -0.1, -0j, -0.1j)",
        "((((-0, -0.1, -0j, -0.1j))))",
        "((-0, -0.1), -0j, -0.1j)",
        "((-0, -0.1), (-0j, -0.1j))",
    ] {
        assert_match_folded(
            match_expr,
            4,
            &[
                "Constant(value=0)",
                "Constant(value=-0.1)",
                "Constant(value=0j)",
                "Constant(value=-0.1j)",
            ],
        );
    }

    assert_output(
        "import ast\nsrc = 'match a:\\n    case 1+2j:\\n        pass'\nfor optval in [0, 1, 2]:\n    value = ast.parse(src, optimize=optval).body[0].cases[0].pattern.value\n    print(optval, type(value).__name__, getattr(value, 'value', None) == 1 + 2j)",
        &["0 BinOp False", "1 Constant True", "2 Constant True"],
    );
}

