fn cpython_ast_validator_simple_comp_source(factory: &str) -> String {
    format!(
        "import ast\n\ndef expr(node, msg):\n    tree = ast.Module([ast.Expr(node)], [])\n    tree.lineno = 0\n    tree.col_offset = 0\n    ast.fix_missing_locations(tree)\n    try:\n        compile(tree, '<test>', 'exec')\n    except ValueError as error:\n        print(error.__class__.__name__, msg in str(error))\n\nfactory = ast.{factory}\ng = ast.comprehension(ast.Name('x', ast.Store()), ast.Name('x', ast.Load()), [], 0)\nexpr(factory(ast.Name('x', ast.Store()), [g]), 'must have Load context')\ndef wrap(gens):\n    return factory(ast.Name('x', ast.Store()), gens)\nexpr(wrap([]), 'comprehension with no generators')\ng = ast.comprehension(ast.Name('x', ast.Load()), ast.Name('x', ast.Load()), [], 0)\nexpr(wrap([g]), 'must have Store context')\ng = ast.comprehension(ast.Name('x', ast.Store()), ast.Name('x', ast.Store()), [], 0)\nexpr(wrap([g]), 'must have Load context')\nx = ast.Name('x', ast.Store())\ny = ast.Name('y', ast.Load())\ng = ast.comprehension(x, y, [None], 0)\nexpr(wrap([g]), 'None disallowed')\ng = ast.comprehension(x, y, [ast.Name('x', ast.Store())], 0)\nexpr(wrap([g]), 'must have Load context')"
    )
}

