// Adapted from CPython `ASTValidatorTests.test_expr`, `test_boolop`,
// `test_unaryop`, `test_yield`, and `test_compare`.
#[test]
fn cpython_ast_validator_core_expr_exact_subset() {
    assert_output(
        "import ast\n\ndef expr(node, msg=None):\n    tree = ast.Module([ast.Expr(node)], [])\n    tree.lineno = 0\n    tree.col_offset = 0\n    ast.fix_missing_locations(tree)\n    if msg is None:\n        compile(tree, '<test>', 'exec')\n        print('ok')\n        return\n    try:\n        compile(tree, '<test>', 'exec')\n    except ValueError as error:\n        print(error.__class__.__name__, msg in str(error))\n\ndef stmt(node, msg):\n    tree = ast.Module([node], [])\n    tree.lineno = 0\n    tree.col_offset = 0\n    ast.fix_missing_locations(tree)\n    try:\n        compile(tree, '<test>', 'exec')\n    except ValueError as error:\n        print(error.__class__.__name__, msg in str(error))\n\nstmt(ast.Expr(ast.Name('x', ast.Store())), 'must have Load context')\nexpr(ast.BoolOp(ast.And(), []), 'less than 2 values')\nexpr(ast.BoolOp(ast.And(), [ast.Constant(3)]), 'less than 2 values')\nexpr(ast.BoolOp(ast.And(), [ast.Constant(4), None]), 'None disallowed')\nexpr(ast.BoolOp(ast.And(), [ast.Constant(4), ast.Name('x', ast.Store())]), 'must have Load context')\nexpr(ast.UnaryOp(ast.Not(), ast.Name('x', ast.Store())), 'must have Load context')\nexpr(ast.Yield(ast.Name('x', ast.Store())), 'must have Load')\nexpr(ast.YieldFrom(ast.Name('x', ast.Store())), 'must have Load')\nleft = ast.Name('x', ast.Load())\nexpr(ast.Compare(left, [ast.In()], []), 'no comparators')\nexpr(ast.Compare(left, [ast.In()], [ast.Constant(4), ast.Constant(5)]), 'different number of comparators and operands')\nexpr(ast.Compare(ast.Constant('blah'), [ast.In()], [left]))\nexpr(ast.Compare(left, [ast.In()], [ast.Constant('blah')]))",
        &[
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ValueError True",
            "ok",
            "ok",
        ],
    );
}

