#[test]
fn cpython_ast_docstring_optimization_single_node_subset() {
    assert_output(
        "import ast\nsources = [\n    '\\nclass A:\\n    \"\"\"Docstring\"\"\"\\n',\n    '\\ndef some():\\n    \"\"\"Docstring\"\"\"\\n',\n    '\\nasync def some():\\n    \"\"\"Docstring\"\"\"\\n',\n]\nfor source in sources:\n    for opt in [0, 1, 2]:\n        mod = ast.parse(source, optimize=opt)\n        stmt = mod.body[0].body[0]\n        if opt == 2:\n            print(type(stmt).__name__, stmt.lineno, stmt.col_offset, stmt.end_lineno, stmt.end_col_offset)\n        else:\n            print(type(stmt).__name__, type(stmt.value).__name__)\n        compile(source, 'a', 'exec')\n        compile(source, 'a', 'exec', optimize=opt)\n        compile(mod, 'a', 'exec')\n        compile(mod, 'a', 'exec', optimize=opt)",
        &[
            "Expr Constant",
            "Expr Constant",
            "Pass 3 4 3 8",
            "Expr Constant",
            "Expr Constant",
            "Pass 3 4 3 8",
            "Expr Constant",
            "Expr Constant",
            "Pass 3 4 3 8",
        ],
    );
}

