#[test]
fn cpython_ast_compile_public_ast_statement_second_pass_subset() {
    assert_output(
        r#"import ast
source = """
import ast as ast_mod
from math import sqrt as root
x: int = 1
x += 8
assert x == 9
items = [1, 2, 3]
del items[1:]
value = 0
def set_value():
    global value
    value = 10
set_value()
def outer():
    local = 1
    def inner():
        nonlocal local
        local = 2
    inner()
    return local
print(root(x), items, value, outer(), type(ast_mod.parse("1")).__name__)
"""
exec(compile(ast.parse(source), "<ast>", "exec"))
"#,
        &["3.0 [1] 10 2 Module"],
    );
}

