// Adapted from CPython `CopyTests` in Lib/test/test_ast/test_ast.py. This
// ports the first shallow `copy.replace()` / `__replace__()` AST-node behavior
// without the larger pickle/deepcopy surface.
#[test]
fn cpython_ast_copy_replace_first_pass_subset() {
    assert_output(
        r#"import ast
import copy

node = ast.Name(id="x", ctx=ast.Load())
ctx = node.ctx
repl = copy.replace(node, id="y")
print(node.id, repl.id, repl.ctx is ctx, repl is node)

node.extra = object()
repl = copy.replace(node)
print(repl.id, repl.ctx is ctx, hasattr(repl, "extra"), hasattr(node, "extra"))

try:
    copy.replace(node, extra=1)
except TypeError as error:
    print(error.__class__.__name__, error)

del node.id
try:
    copy.replace(node)
except TypeError as error:
    print(error.__class__.__name__, error)
repl = copy.replace(node, id="z")
print(hasattr(node, "id"), repl.id, repl.ctx is ctx)

fn = ast.FunctionDef(name="foo", args=ast.arguments())
fn2 = copy.replace(fn, name="bar")
print(fn.name, fn2.name, fn2.returns, fn2.decorator_list)

parsed = ast.parse("x").body[0].value
lineno = object()
parsed2 = copy.replace(parsed, lineno=lineno)
print(parsed.lineno, parsed2.lineno is lineno, parsed2.id == parsed.id, parsed2.ctx is parsed.ctx)

class MyNode(ast.AST):
    _fields = ("name", "data")
    __match_args__ = ("name", "data")
name = "name"
data = object()
node = MyNode(name, data)
repl = copy.replace(node)
print(repl.name == name, repl.data is data, repl is node)
new_data = object()
repl = copy.replace(node, data=new_data)
print(repl.name == name, repl.data is new_data, node.data is data)

class MyAttrs(ast.AST):
    x = 0
    y = 1
    _attributes = ("x", "y")
node = MyAttrs()
marker = object()
repl = copy.replace(node, y=marker)
print(repl.x, repl.y is marker, node.y)

try:
    ast.Name(id="x").__replace__(1)
except TypeError as error:
    print(error.__class__.__name__, "positional" in str(error))
try:
    ast.Name(id="x").__replace__(**{object(): "y"})
except TypeError as error:
    print(error.__class__.__name__, "unexpected keyword argument <object object>" in str(error))"#,
        &[
            "x y True False",
            "x True False True",
            "TypeError Name.__replace__ got an unexpected keyword argument 'extra'.",
            "TypeError Name.__replace__ missing 1 keyword argument: 'id'.",
            "False z True",
            "foo bar None []",
            "1 True True True",
            "True True False",
            "True True True",
            "0 True 1",
            "TypeError True",
            "TypeError True",
        ],
    );
}

