// the cyclic AST-object graph that matters for parent links without pulling in
// CPython's stack-limit support helpers.
#[test]
fn cpython_ast_deepcopy_parent_links_first_pass_subset() {
    assert_output(
        r#"import ast
import copy

source = """
('',)
while i < n:
    if ch == '':
        ch = format[i]
        if ch == '':
            if freplace is None:
                '' % getattr(object)
        elif ch == '':
            if zreplace is None:
                if hasattr:
                    offset = object.utcoffset()
                    if offset is not None:
                        if offset.days < 0:
                            offset = -offset
                        h = divmod(timedelta(hours=0))
                        if u:
                            zreplace = '' % (sign,)
                        elif s:
                            zreplace = '' % (sign,)
                        else:
                            zreplace = '' % (sign,)
        elif ch == '':
            if Zreplace is None:
                Zreplace = ''
                if hasattr(object):
                    s = object.tzname()
                    if s is not None:
                        Zreplace = s.replace('')
            newformat.append(Zreplace)
        else:
            push('')
    else:
        push(ch)
"""

tree = ast.parse(source)
for node in ast.walk(tree):
    for child in ast.iter_child_nodes(node):
        child.parent = node

tree2 = copy.deepcopy(tree)
for node in ast.walk(tree):
    if hasattr(node, "parent"):
        del node.parent

checked = 0
same_parent = 0
structural_parent = 0
for node in ast.walk(tree2):
    for child in ast.iter_child_nodes(node):
        if hasattr(child, "parent") and not isinstance(child, (ast.expr_context, ast.boolop, ast.unaryop, ast.cmpop, ast.operator)):
            checked += 1
            if child.parent is node:
                same_parent += 1
            if ast.compare(child.parent, node):
                structural_parent += 1

print(tree2 is tree)
print(checked > 0, same_parent == checked, structural_parent == checked)
print(any(hasattr(node, "parent") for node in ast.walk(tree)))
print(isinstance(ast.Add(), ast.operator), isinstance(ast.And(), ast.boolop), isinstance(ast.Not(), ast.unaryop), isinstance(ast.Eq(), ast.cmpop))"#,
        &["False", "True True True", "False", "True True True True"],
    );
}

// Adapted from CPython `CopyTests.test_pickling`. MiniPython does not expose
// CPython's binary pickle protocol yet; this ports the observable AST
// round-trip semantics through the minimal `pickle.dumps()` / `pickle.loads()`
// surface over public AST trees.
#[test]
fn cpython_ast_pickle_roundtrip_first_pass_subset() {
    assert_output(
        r#"import ast
import pickle

codes = [
    "x = 1\n",
    "def f(a, /, b=2, *args, c, **kw):\n    return a + b\n",
    "match value:\n    case [head, *tail] if head:\n        result = tail\n",
    "async def main():\n    async for value in source:\n        await sink(value)\n",
]

checked = 0
same_identity = 0
for protocol in range(pickle.HIGHEST_PROTOCOL + 1):
    for code in codes:
        tree = compile(code, "?", "exec", 0x400)
        ast2 = pickle.loads(pickle.dumps(tree, protocol))
        if ast.compare(ast2, tree, compare_attributes=True):
            checked += 1
        if ast2 is tree:
            same_identity += 1
print(checked, len(codes) * (pickle.HIGHEST_PROTOCOL + 1), same_identity)

tree = compile("x = 1\n", "?", "exec", 0x400)
payload = pickle.dumps(tree)
tree.body = []
ast2 = pickle.loads(payload)
print(len(ast2.body), len(tree.body), ast.compare(ast2, tree))"#,
        &["24 24 0", "1 0 False"],
    );
}

// Adapted from CPython `CopyTests.test_replace_interface` and
// `CopyTests.test_replace_native`. This keeps the original recursive native
// `ast.AST.__subclasses__()` shape and checks the class-level `__replace__`
// surface plus shallow field/location-attribute replacement across every
// exposed native AST class.
#[test]
fn cpython_ast_replace_native_class_iteration_first_pass_subset() {
    assert_output(
        r#"import ast
import copy

def iter_ast_classes():
    def do(cls):
        if cls.__module__ != "ast":
            return
        if hasattr(ast, "Index") and cls is ast.Index:
            return
        yield cls
        for sub in cls.__subclasses__():
            yield from do(sub)
    yield from do(ast.AST)

classes = list(iter_ast_classes())
print(len(classes) > 50, ast.AST in classes, ast.expr in classes, ast.Name in classes, ast.Add in classes, ast.MatchClass in classes)
print(issubclass(ast.Name, ast.expr), isinstance(ast.Name("x"), ast.expr), ast.Name.__bases__[0] is ast.expr)
print(ast.expr in ast.AST.__subclasses__(), ast.Name in ast.expr.__subclasses__(), ast.Load in ast.expr_context.__subclasses__())

missing_replace = 0
constructed = 0
copy_positional_errors = 0
method_positional_errors = 0
same_copies = 0
field_changes = 0
attribute_changes = 0
total_fields = 0
total_attributes = 0

for klass in classes:
    if not hasattr(klass, "__replace__"):
        missing_replace += 1

    fields = list(klass._fields)
    attributes = list(klass._attributes)
    old_fields = {field: object() for field in fields}
    old_attrs = {attr: object() for attr in attributes}
    total_fields += len(fields)
    total_attributes += len(attributes)

    node = klass(**dict.fromkeys(set(fields)))
    constructed += 1
    try:
        copy.replace(node, 1)
    except TypeError:
        copy_positional_errors += 1
    try:
        node.__replace__(1)
    except TypeError:
        method_positional_errors += 1

    node = klass(**old_fields)
    repl = copy.replace(node)
    if ast.compare(node, repl, compare_attributes=True):
        same_copies += 1

    node = klass(**old_fields, **old_attrs)
    repl = copy.replace(node)
    if ast.compare(node, repl, compare_attributes=True):
        same_copies += 1

    for field in fields:
        node = klass(**old_fields, **old_attrs)
        old_value = getattr(node, field)
        marker = object()
        repl = copy.replace(node, **{field: marker})
        if getattr(node, field) is old_value and getattr(repl, field) is marker and not ast.compare(node, repl, compare_attributes=True):
            field_changes += 1

    for attribute in attributes:
        node = klass(**old_fields, **old_attrs)
        old_value = getattr(node, attribute)
        marker = object()
        repl = copy.replace(node, **{attribute: marker})
        if getattr(node, attribute) is old_value and getattr(repl, attribute) is marker and not ast.compare(node, repl, compare_attributes=True):
            attribute_changes += 1

print(missing_replace, constructed == len(classes), copy_positional_errors == len(classes), method_positional_errors == len(classes))
print(same_copies == len(classes) * 2, field_changes == total_fields, attribute_changes == total_attributes, total_fields > 100, total_attributes > 0)"#,
        &[
            "True True True True True True",
            "True True True",
            "True True True",
            "0 True True True",
            "True True True True True",
        ],
    );
}

