#[test]
fn cpython_ast_copy_replace_native_exact_subset() {
    assert_output(
        r#"import ast
import copy

def iter_ast_classes():
    def do(cls):
        if cls.__module__ != "ast":
            return
        if hasattr(ast, "Index") and cls is ast.Index:
            return
        yield cls
        for sub in cls.__subclasses__():
            yield from do(sub)
    yield from do(ast.AST)

same_copies = 0
field_changes = 0
attribute_changes = 0
total_fields = 0
total_attributes = 0
classes = list(iter_ast_classes())
for klass in classes:
    fields = set(klass._fields)
    attributes = set(klass._attributes)
    old_fields = {field: object() for field in fields}
    old_attrs = {attr: object() for attr in attributes}
    total_fields += len(fields)
    total_attributes += len(attributes)

    node = klass(**old_fields)
    repl = copy.replace(node)
    if ast.compare(node, repl, compare_attributes=True):
        same_copies += 1

    node = klass(**old_fields, **old_attrs)
    repl = copy.replace(node)
    if ast.compare(node, repl, compare_attributes=True):
        same_copies += 1

    for field in fields:
        for init_attrs in [{}, old_attrs]:
            node = klass(**old_fields, **init_attrs)
            old_value = getattr(node, field)
            new_value = object()
            repl = copy.replace(node, **{field: new_value})
            if getattr(node, field) is old_value and getattr(repl, field) is new_value and not ast.compare(node, repl, compare_attributes=True):
                field_changes += 1

    for attribute in attributes:
        node = klass(**old_fields, **old_attrs)
        old_attr = getattr(node, attribute)
        new_attr = object()
        repl = copy.replace(node, **{attribute: new_attr})
        if getattr(node, attribute) is old_attr and getattr(repl, attribute) is new_attr and not ast.compare(node, repl, compare_attributes=True):
            attribute_changes += 1

print(same_copies == len(classes) * 2, field_changes == total_fields * 2, attribute_changes == total_attributes, total_fields > 100, total_attributes > 0)"#,
        &["True True True True True"],
    );
}

