#[test]
fn cpython_ast_node_transformer_first_pass_subset() {
    assert_output(
        r#"import ast
print(ast.NodeVisitor.__module__, ast.NodeTransformer.__module__)
print(issubclass(ast.NodeTransformer, ast.NodeVisitor), isinstance(ast.NodeTransformer(), ast.NodeVisitor))
class CountingVisitor(ast.NodeVisitor):
    def __init__(self):
        self.names = []
    def visit_Name(self, node):
        self.names.append(node.id)
        self.generic_visit(node)
visitor = CountingVisitor()
print(visitor.visit(ast.parse("x = y + 1")), visitor.names)
class SomeTypeRemover(ast.NodeTransformer):
    def visit_Name(self, node):
        self.generic_visit(node)
        if node.id == "SomeType":
            return None
        return node
tree = SomeTypeRemover().visit(ast.parse("def func(arg) -> SomeType: ..."))
print(hasattr(tree.body[0], "returns"))
class YieldRemover(ast.NodeTransformer):
    def visit_Expr(self, node):
        self.generic_visit(node)
        if isinstance(node.value, ast.Yield):
            return None
        return node
tree = YieldRemover().visit(ast.parse("def func(arg):\n    print(arg)\n    yield arg"))
print(len(tree.body[0].body), type(tree.body[0].body[0].value.func).__name__)
class ExtendKeywords(ast.NodeTransformer):
    def visit_keyword(self, node):
        self.generic_visit(node)
        if node.arg == "kw1":
            return [
                node,
                ast.keyword("kw2", ast.Constant(True)),
                ast.keyword("kw3", ast.Constant(False)),
            ]
        return node
tree = ExtendKeywords().visit(ast.parse("class DSL(Base, kw1=True): ..."))
print([kw.arg for kw in tree.body[0].keywords], [kw.value.value for kw in tree.body[0].keywords])
class MutatePrint(ast.NodeTransformer):
    def visit_Call(self, node):
        self.generic_visit(node)
        if isinstance(node.func, ast.Name) and node.func.id == "print":
            node.func.id = "log"
        return node
tree = MutatePrint().visit(ast.parse("def func(arg):\n    print(arg)"))
print(tree.body[0].body[0].value.func.id)
class ReplacePrint(ast.NodeTransformer):
    def visit_Call(self, node):
        self.generic_visit(node)
        if isinstance(node.func, ast.Name) and node.func.id == "print":
            return ast.Call(
                func=ast.Attribute(ast.Name("logger", ast.Load()), "log", ast.Load()),
                args=node.args,
                keywords=[ast.keyword("debug", ast.Constant(True))],
            )
        return node
tree = ReplacePrint().visit(ast.parse("def func(arg):\n    print(arg)"))
call = tree.body[0].body[0].value
print(type(call.func).__name__, call.func.value.id, call.func.attr, call.keywords[0].arg, call.keywords[0].value.value)
"#,
        &[
            "ast ast",
            "True True",
            "None ['x', 'y']",
            "False",
            "1 Name",
            "['kw1', 'kw2', 'kw3'] [True, True, False]",
            "log",
            "Attribute logger log debug True",
        ],
    );
}

#[test]
fn cpython_ast_literal_eval_first_pass_subset() {
    assert_output(
        "import ast\nprint(ast.literal_eval('[1, 2, 3]'))\nprint(ast.literal_eval('{\"foo\": 42}'))\nprint(ast.literal_eval('(True, False, None)'))\nprint(sorted(list(ast.literal_eval('{1, 2, 3}'))))\nprint(ast.literal_eval('b\"hi\"'))\nprint(ast.literal_eval('set()') == set())\nprint(ast.literal_eval('6'), ast.literal_eval('+6'), ast.literal_eval('-6'))\nprint(ast.literal_eval('3.25'), ast.literal_eval('+3.25'), ast.literal_eval('-3.25'))\nprint(repr(ast.literal_eval('-0.0')))\nprint(ast.literal_eval('6j') == 6j, ast.literal_eval('-6j') == -6j)\nprint(ast.literal_eval('3+6j') == 3+6j, ast.literal_eval('-3.25-6.75j') == -3.25-6.75j)\nnode = ast.parse('[1, 2]', mode='eval').body\nprint(ast.literal_eval(node))\nfor source in ['foo()', '++6', '+True', '2+3', '-6j+3', '-6j+3j', '3+-6j', '3+(0+6j)', '-(3+6j)']:\n    try:\n        ast.literal_eval(source)\n    except ValueError as error:\n        print(error.__class__.__name__)",
        &[
            "[1, 2, 3]",
            "{'foo': 42}",
            "(True, False, None)",
            "[1, 2, 3]",
            "b'hi'",
            "True",
            "6 6 -6",
            "3.25 3.25 -3.25",
            "-0.0",
            "True True",
            "True True",
            "[1, 2]",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
        ],
    );
}

