#[test]
fn cpython_ast_literal_eval_diagnostics_first_pass_subset() {
    assert_output(
        "import ast\nfor malformed in [ast.Dict(keys=[ast.Constant(1), ast.Constant(2)], values=[ast.Constant(3)]), ast.Dict(keys=[ast.Constant(1)], values=[ast.Constant(2), ast.Constant(3)])]:\n    try:\n        ast.literal_eval(malformed)\n    except ValueError as error:\n        print(error.__class__.__name__)\nfor source in ['    -1', '\\t\\t-1', ' \\t -1']:\n    print(ast.literal_eval(source))\ntry:\n    ast.literal_eval('\\n -1')\nexcept IndentationError as error:\n    print(error.__class__.__name__, 'unexpected indent' in str(error))\ntry:\n    ast.literal_eval(r'''\n                \\\n                (\\\n            \\ ''')\nexcept SyntaxError as error:\n    print(error.__class__.__name__, 'unexpected indent' in str(error))\ntry:\n    ast.literal_eval(\"{'a': 1,\\n'b':2,\\n'c':++3,\\n'd':4}\")\nexcept ValueError as error:\n    print(error.__class__.__name__, 'on line 3' in str(error))\nnode = ast.UnaryOp(ast.UAdd(), ast.UnaryOp(ast.UAdd(), ast.Constant(6)))\nprint(getattr(node, 'lineno', None) is None)\ntry:\n    ast.literal_eval(node)\nexcept ValueError as error:\n    print(error.__class__.__name__, 'on line' in str(error), 'malformed node or string:' in str(error))",
        &[
            "ValueError",
            "ValueError",
            "-1",
            "-1",
            "-1",
            "IndentationError True",
            "IndentationError True",
            "ValueError True",
            "True",
            "ValueError False True",
        ],
    );
}

