// Adapted from CPython `EndPositionTests.test_suites`.
#[test]
fn cpython_ast_suites_end_positions_exact_subset() {
    assert_output(
        "import ast\nsource = 'while True:\\n    pass\\n\\nif one():\\n    x = None\\nelif other():\\n    y = None\\nelse:\\n    z = None\\n\\nfor x, y in stuff:\\n    assert True\\n\\ntry:\\n    raise RuntimeError\\nexcept TypeError as e:\\n    pass\\n\\npass'\nmod = ast.parse(source)\nwhile_loop = mod.body[0]\nif_stmt = mod.body[1]\nfor_loop = mod.body[2]\ntry_stmt = mod.body[3]\npass_stmt = mod.body[4]\nprint(while_loop.end_lineno, while_loop.end_col_offset)\nprint(if_stmt.end_lineno, if_stmt.end_col_offset)\nprint(for_loop.end_lineno, for_loop.end_col_offset)\nprint(try_stmt.end_lineno, try_stmt.end_col_offset)\nprint(pass_stmt.end_lineno, pass_stmt.end_col_offset)\nprint(ast.get_source_segment(source, while_loop.test))\nprint(ast.get_source_segment(source, if_stmt.body[0]))\nprint(ast.get_source_segment(source, if_stmt.orelse[0].test))\nprint(ast.get_source_segment(source, for_loop.target))\nprint(ast.get_source_segment(source, try_stmt.body[0]))\nprint(ast.get_source_segment(source, try_stmt.handlers[0].type))",
        &[
            "2 8",
            "9 12",
            "12 15",
            "17 8",
            "19 4",
            "True",
            "x = None",
            "other()",
            "x, y",
            "raise RuntimeError",
            "TypeError",
        ],
    );
}

