// Adapted from CPython's `Lib/test/test_grammar.py::test_control_flow_in_finally`.
// MiniPython checks the same observable override semantics: control flow inside
// `finally` can suppress an active exception, break, continue, or return.
#[test]
fn cpython_control_flow_in_finally_subset() {
    assert_output(
        "result = 0\nwhile result < 2:\n    result += 1\n    try:\n        1 / 0\n    finally:\n        break\nprint(result)",
        &["1"],
    );
    assert_output(
        "result = 0\nwhile result < 2:\n    result += 1\n    try:\n        break\n    finally:\n        continue\nprint(result)",
        &["2"],
    );
    assert_output(
        "def f():\n    try:\n        1 / 0\n    finally:\n        return 4\nprint(f())",
        &["4"],
    );
    assert_output(
        "def f(x):\n    for count in [0, 1]:\n        while True:\n            try:\n                return count + 10\n            finally:\n                if x:\n                    break\n    return (\"end\", count)\nprint(f(False))\nprint(f(True))",
        &["10", "('end', 1)"],
    );
    assert_output(
        "def f(x):\n    count = 0\n    while count < 3:\n        count += 1\n        try:\n            return count\n        finally:\n            if x:\n                continue\n    return (\"end\", count)\nprint(f(False))\nprint(f(True))",
        &["1", "('end', 3)"],
    );
}

// Adapted from CPython's Lib/test/test_syntax.py::test_return_in_finally and
// ::test_break_and_continue_in_finally. MiniPython exposes these as lightweight
// static SyntaxWarning messages through the same warning API used for tokenizer
// SyntaxWarnings.
#[test]
fn cpython_finally_control_flow_warning_subset() {
    assert_warnings(
        "def f():\n    try:\n        pass\n    finally:\n        return 42",
        &["'return' in a 'finally' block"],
    );
    assert_warnings(
        "def f():\n    try:\n        pass\n    finally:\n        try:\n            return 42\n        except:\n            pass",
        &["'return' in a 'finally' block"],
    );
    assert_warnings(
        "def f():\n    try:\n        pass\n    finally:\n        try:\n            pass\n        except:\n            return 42",
        &["'return' in a 'finally' block"],
    );
    assert_warnings(
        "for abc in range(10):\n    try:\n        pass\n    finally:\n        break",
        &["'break' in a 'finally' block"],
    );
    assert_warnings(
        "for abc in range(10):\n    try:\n        pass\n    finally:\n        try:\n            break\n        except:\n            pass",
        &["'break' in a 'finally' block"],
    );
    assert_warnings(
        "for abc in range(10):\n    try:\n        pass\n    finally:\n        try:\n            pass\n        except:\n            break",
        &["'break' in a 'finally' block"],
    );
    assert_warnings(
        "for abc in range(10):\n    try:\n        pass\n    finally:\n        continue",
        &["'continue' in a 'finally' block"],
    );
    assert_warnings(
        "for abc in range(10):\n    try:\n        pass\n    finally:\n        try:\n            continue\n        except:\n            pass",
        &["'continue' in a 'finally' block"],
    );
    assert_warnings(
        "for abc in range(10):\n    try:\n        pass\n    finally:\n        try:\n            pass\n        except:\n            continue",
        &["'continue' in a 'finally' block"],
    );
    assert_warnings(
        "for abc in range(10):\n    try:\n        pass\n    finally:\n        def nested():\n            return 42",
        &[],
    );
    assert_warning_as_error(
        "def f():\n    try:\n        pass\n    finally:\n        return 42",
        "'return' in a 'finally' block",
    );
}

// Adapted from CPython grammar `try_stmt` / `except_star_block` coverage in
// Lib/test/test_grammar.py::test_try_star and invalid-mixing coverage in
// Lib/test/test_except_star.py. MiniPython currently parses `TryStar` separately
// and executes it with its builtin exception subset.
#[test]
fn cpython_grammar_try_star_subset() {
    assert_output(
        "try:\n    1/0\nexcept* ZeroDivisionError:\n    pass\nelse:\n    pass",
        &[],
    );
    assert_output(
        "try: 1/0\nexcept* EOFError: pass\nexcept* ZeroDivisionError as msg: pass\nelse: pass",
        &[],
    );
    assert_output(
        "try: 1/0\nexcept* (EOFError, TypeError, ZeroDivisionError): pass",
        &[],
    );
    assert_output(
        "try: 1/0\nexcept* EOFError, TypeError, ZeroDivisionError: pass",
        &[],
    );
    assert_output(
        "try: 1/0\nexcept* (EOFError, TypeError, ZeroDivisionError) as msg: pass",
        &[],
    );
    assert_output("try: pass\nfinally: pass", &[]);
    assert_parse_error("try:\n    pass\nexcept* Exception as a.b:\n    pass");
    assert_parse_error("try:\n    pass\nexcept* Exception as a[b]:\n    pass");
    assert_parse_error("try:\n    pass\nexcept*:\n    pass");
    assert_output(
        "try:\n    raise ValueError(\"bad\")\nexcept* TypeError:\n    print(\"type\")\nexcept* ValueError:\n    print(\"value\")\nelse:\n    print(\"else\")",
        &["value"],
    );
    assert_output(
        "try:\n    print(\"body\")\nexcept* ValueError as group:\n    print(\"value\", group)\nelse:\n    print(\"else\")\nfinally:\n    print(\"finally\")",
        &["body", "else", "finally"],
    );
    assert_output(
        "try:\n    raise TypeError(\"bad\")\nexcept* (ValueError, TypeError):\n    print(\"tuple\")",
        &["tuple"],
    );
    assert_output(
        "try:\n    raise ValueError(\"bad\")\nexcept* TypeError, ValueError:\n    print(\"comma\")",
        &["comma"],
    );
    assert_output(
        "try:\n    raise ExceptionGroup(\"eg\", [ValueError(\"bad\")])\nexcept* ValueError as group:\n    print(group.__class__.__name__, group.exceptions[0])\nfinally:\n    print(\"finally\")",
        &["ExceptionGroup bad", "finally"],
    );
    assert_parse_error("try:\n    pass\nexcept* TypeError, ValueError as error:\n    pass");
    assert_parse_error("try:\n    pass\nexcept*:\n    pass");
    assert_parse_error("try:\n    pass\nexcept* TypeError as handler():\n    pass");
    assert_parse_error("try:\n    pass\nexcept* TypeError\n    pass");
    assert_error(
        "try:\n    pass\nexcept ValueError:\n    pass\nexcept* TypeError:\n    pass",
        "parse error: cannot have both 'except' and 'except*' on the same 'try'",
    );
    assert_error(
        "try:\n    raise ValueError(\"bad\")\nexcept* ValueError:\n    return",
        "compile error: 'break', 'continue' and 'return' cannot appear in an except* block",
    );
}

// Adapted from CPython's invalid `except* ExceptionGroup` runtime checks in
// Lib/test/test_except_star.py::TestInvalidExceptStar.
#[test]
fn cpython_except_star_rejects_exception_group_types_subset() {
    let message = "catching ExceptionGroup with except* is not allowed. Use except instead.";
    assert_output(
        "try:\n    try:\n        raise OSError(\"blah\")\n    except* ExceptionGroup as error:\n        print(\"wrong\", error)\nexcept TypeError as error:\n    print(error)",
        &[message],
    );
    assert_output(
        "try:\n    try:\n        raise ExceptionGroup(\"eg\", [ValueError(\"V\")])\n    except* (TypeError, ExceptionGroup):\n        print(\"wrong\")\nexcept TypeError as error:\n    print(error)",
        &[message],
    );
}

// Adapted from CPython's ExceptionGroup split coverage in
// Lib/test/test_except_star.py::TestExceptStarSplitSemantics. MiniPython checks
// observable split/rest behavior for flat and nested ExceptionGroup subsets.
#[test]
fn cpython_except_star_split_semantics_subset() {
    assert_output(
        "try:\n    try:\n        raise ExceptionGroup(\"eg\", [ValueError(\"V\"), TypeError(\"T\")])\n    except* ValueError as matched:\n        print(\"matched\", matched.message, matched.exceptions[0].__class__.__name__, matched.exceptions[0])\nexcept ExceptionGroup as rest:\n    print(\"rest\", rest.message, rest.exceptions[0].__class__.__name__, rest.exceptions[0])",
        &["matched eg ValueError V", "rest eg TypeError T"],
    );
    assert_output(
        "try:\n    raise ExceptionGroup(\"eg\", [ValueError(\"V\"), TypeError(\"T\")])\nexcept* ValueError as value_group:\n    print(\"value\", value_group.exceptions[0])\nexcept* TypeError as type_group:\n    print(\"type\", type_group.exceptions[0])\nprint(\"done\")",
        &["value V", "type T", "done"],
    );
    assert_output(
        "try:\n    raise ValueError(\"V\")\nexcept* ValueError as group:\n    print(group.__class__.__name__, group.exceptions[0].__class__.__name__, group.exceptions[0])",
        &["ExceptionGroup ValueError V"],
    );
    assert_output(
        "try:\n    try:\n        raise ExceptionGroup(\"outer\", [ValueError(\"V1\"), ExceptionGroup(\"inner\", [TypeError(\"T\"), ValueError(\"V2\")])])\n    except* ValueError as matched:\n        print(\"matched\", matched.message, matched.exceptions[0], matched.exceptions[1].message, matched.exceptions[1].exceptions[0])\nexcept ExceptionGroup as rest:\n    print(\"rest\", rest.message, rest.exceptions[0].message, rest.exceptions[0].exceptions[0])",
        &["matched outer V1 inner V2", "rest outer inner T"],
    );
}

