// Adapted from CPython grammar `function_def_raw`, whose valid alternatives are
// ordinary `def` and `async def` headers with optional type parameters, params,
// return annotations, function type comments, and either inline or indented
// blocks. Invalid header shapes are covered by
// `cpython_invalid_function_def_raw_subset`.
#[test]
fn cpython_function_def_raw_rule_subset() {
    assert_output(
        "def typed():  # type: () -> int\n    return 9\nprint(typed())",
        &["9"],
    );
    assert_output(
        "def f[T](x: T, y: int = 2, *args: str, flag: bool = True, **kwargs: list) -> T:\n    return x\nprint(f(5, \"extra\", flag=False, bonus=9), f.__type_params__[0].__name__, f.__annotations__[\"x\"].__name__, f.__annotations__[\"return\"].__name__)",
        &["5 T T T"],
    );
    assert_output(
        "async def coro[T = int](value: T) -> T: return value\nc = coro(7)\ntry:\n    coro_result = c.send(None)\nexcept StopIteration as done:\n    print(done, coro.__type_params__[0].__default__.__name__, coro.__annotations__[\"value\"].__name__, coro.__annotations__[\"return\"].__name__)",
        &["7 int T T"],
    );
}

// Adapted from CPython grammar `function_def`, which is either decorators plus
