// Adapted from CPython grammar `class_def` and primary selector coverage.
// MiniPython checks class bodies, class attributes, instance creation,
// positional bases, and unpacked class-header arguments through observable
// runtime behavior.
#[test]
fn cpython_grammar_class_def_subset() {
    assert_output(
        "class Box:\n    pass\nbox = Box()\nbox.value = 3\nprint(box.value)",
        &["3"],
    );
    assert_output("class Inline: pass\nprint(Inline.__name__)", &["Inline"]);
    assert_output(
        "class Thing:\n    kind = \"thing\"\nprint(Thing.__name__, Thing.kind)\nThing.kind = \"changed\"\nprint(Thing.kind)",
        &["Thing thing", "changed"],
    );
    assert_output(
        "class Counter:\n    def __init__(self, start):\n        self.value = start\n    def inc(self):\n        self.value += 1\n        return self.value\nc = Counter(2)\nprint(c.value, c.inc(), c.value)",
        &["2 3 3"],
    );
    assert_output(
        "class Base:\n    kind = \"base\"\n    def __init__(self, value):\n        self.value = value\nclass Child(Base):\n    pass\nc = Child(4)\nprint(Child.__bases__[0].__name__, Child.kind, c.value)",
        &["Base base 4"],
    );
    assert_output(
        "class Base:\n    label = \"base\"\nbases = (Base,)\nkwargs = {'metaclass': Base}\nclass FromUnpack(*bases, **kwargs):\n    pass\nprint(FromUnpack.__bases__[0].__name__, FromUnpack.label)",
        &["Base base"],
    );
}

// Adapted from CPython Lib/test/test_grammar.py::GrammarTests.test_classdef.
// CPython's method mainly checks that these class definition and decorator
// shapes compile and execute, so this prints representative metadata and method
// call results for the same source forms.
#[test]
fn cpython_grammar_classdef_method_subset() {
    let source = r#"class B: pass
class B2(): pass
class C1(B): pass
class C2(B): pass
class D(C1, C2, B): pass
class C:
    def meth1(self): pass
    def meth2(self, arg): pass
    def meth3(self, a1, a2): pass

print(B.__name__, B2.__name__)
print(C1.__bases__[0] is B, C2.__bases__[0] is B)
print(D.__bases__[0] is C1, D.__bases__[1] is C2, D.__bases__[2] is B)
c = C()
print(c.meth1(), c.meth2(1), c.meth3(1, 2))

def class_decorator(x): return x
@class_decorator
class G: pass

@False or class_decorator
class H: pass
@d := class_decorator
class I: pass
@lambda c: class_decorator(c)
class J: pass
@[..., class_decorator, ...][1]
class K: pass
@class_decorator(class_decorator)(class_decorator)
class L: pass
@[class_decorator][0].__call__.__call__
class M: pass

print(G.__name__, H.__name__, I.__name__, J.__name__)
print(K.__name__, L.__name__, M.__name__, d.__name__)"#;
    assert_output(
        source,
        &[
            "B B2",
            "True True",
            "True True True",
            "None None None",
            "G H I J",
            "K L M class_decorator",
        ],
    );
}

// Adapted from CPython's `class_def_raw` and `invalid_class_def_raw` grammar
// rules. MiniPython supports the same raw class-header subset for names, type
// params, optional parentheses, base arguments, keyword arguments, and unpacked
// class-header arguments. It rejects the CPython-invalid missing-colon and
// missing-suite shapes before VM execution.
#[test]
fn cpython_class_def_raw_helper_rules_subset() {
    assert_output("class Plain:\n    pass\nprint(Plain.__name__)", &["Plain"]);
    assert_output(
        "class EmptyArgs():\n    pass\nprint(EmptyArgs.__name__)",
        &["EmptyArgs"],
    );
    assert_output(
        "class InlineEmptyArgs(): ...\nprint(InlineEmptyArgs.__name__)",
        &["InlineEmptyArgs"],
    );
    assert_output(
        "class Base:\n    label = \"base\"\nclass Child[T](Base):\n    pass\nprint(Child.__name__, Child.__type_params__[0].__name__, Child.__bases__[0].__name__, Child.label)",
        &["Child T Base base"],
    );
    assert_output(
        "class Base:\n    label = \"base\"\nbases = (Base,)\nkwargs = {'metaclass': Base}\nclass FromArgs[T](*bases, **kwargs):\n    pass\nprint(FromArgs.__name__, FromArgs.__type_params__[0].__name__, FromArgs.__bases__[0].__name__, FromArgs.label)",
        &["FromArgs T Base base"],
    );
    assert_error(
        "class MissingColon\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "class MissingColon[T]\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "class MissingColon(Base)\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "class MissingSuite:\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "class MissingSuite[T](Base):\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "class MissingSuite[T]():\npass",
        "parse error: expected an indented block",
    );
}

