// Adapted from CPython grammar `compound_stmt`, whose alternatives dispatch to
// function, if, class, with, for, try, while, and match statements. Each child
// rule has focused tests elsewhere; this parent-rule test keeps the dispatch
// surface covered in one executable slice.
#[test]
fn cpython_compound_stmt_rule_alternatives_subset() {
    assert_output(
        "def identity(value):\n    return value\n@identity\ndef f(): return 1\nif True:\n    print(\"if\")\nclass C:\n    pass\nclass Manager:\n    def __enter__(self):\n        print(\"enter\")\n        return self\n    def __exit__(self, exc_type, exc, traceback):\n        print(\"exit\", exc_type)\n        return False\nwith Manager():\n    print(\"with\")\nfor value in range(1):\n    print(\"for\", value)\ntry:\n    raise ValueError(\"boom\")\nexcept ValueError as error:\n    print(\"try\", error)\nwhile False:\n    print(\"while body\")\nelse:\n    print(\"while else\")\nmatch 1:\n    case 1:\n        print(\"match\")\nprint(f(), C.__name__)",
        &[
            "if",
            "enter",
            "with",
            "exit None",
            "for 0",
            "try boom",
            "while else",
            "match",
            "1 C",
        ],
    );
}

// Adapted from CPython grammar `decorators`, `function_def`, and `class_def`
// coverage in Lib/test/test_grammar.py and order checks in
// Lib/test/test_decorators.py. MiniPython currently supports expression
// decorators for functions and classes, with top-to-bottom decorator evaluation
// and bottom-to-top application.
#[test]
fn cpython_grammar_decorators_subset() {
    assert_output(
        "def identity(value):\n    return value\n@identity\ndef f():\n    return 3\nprint(f())",
        &["3"],
    );
    assert_output(
        "def callnum(num):\n    def deco(func):\n        return lambda: num\n    return deco\n@callnum(2)\n@callnum(1)\ndef foo():\n    return 42\nprint(foo())",
        &["2"],
    );
    assert_output(
        "actions = \"\"\ndef make(tag):\n    global actions\n    actions = actions + \"make\" + tag\n    def decorate(func):\n        global actions\n        actions = actions + \"call\" + tag\n        return func\n    return decorate\n@make(\"1\")\n@make(\"2\")\ndef foo():\n    return 42\nprint(actions)",
        &["make1make2call2call1"],
    );
    assert_output(
        "def identity(value):\n    return value\n@False or identity\ndef f():\n    return 3\n@d := identity\ndef g():\n    return 4\n@lambda func: func\ndef h():\n    return 5\nprint(f(), d.__name__, g(), h())",
        &["3 identity 4 5"],
    );
    assert_output(
        "def identity(value):\n    return value\n@[identity][0]\ndef f():\n    return 6\nprint(f())",
        &["6"],
    );
    assert_output(
        "def identity(value):\n    return value\n@identity\nasync def main():\n    return 7\ncoro = main()\ntry:\n    coro.send(None)\nexcept StopIteration as done:\n    print(done)",
        &["7"],
    );
    assert_output(
        "def identity(cls):\n    print(cls.__name__)\n    return cls\n@identity\nclass C:\n    pass\nprint(C.__name__)",
        &["C", "C"],
    );
    assert_parse_error("@identity\npass");
    assert_parse_error("@identity def f():\n    pass");
}

