// Adapted from CPython AST dict literal coverage in
// Lib/test/test_ast/snippets.py and grammar dictmaker examples in
// Lib/test/test_grammar.py. MiniPython supports literal key/value pairs,
// lookup by key, truthiness, and default iteration over insertion-ordered keys.
#[test]
fn cpython_ast_dict_literal_subset() {
    assert_output("print({})", &["{}"]);
    assert_output("print({1: 2})", &["{1: 2}"]);
    assert_output(
        "x = {'one': 1, 'two': 2}\nprint(x)",
        &["{'one': 1, 'two': 2}"],
    );
    assert_output("x = {'one': 1,}\nprint(x[\"one\"])", &["1"]);
    assert_output("x = {'one': 1, 'one': 2}\nprint(x)", &["{'one': 2}"]);
    assert_output(
        "x = {\"one\" or \"two\": 1 or 2}\nprint(x)",
        &["{'one': 1}"],
    );
    assert_output("x = {'one': 1, 'two': 2}\nprint(x[\"two\"])", &["2"]);
    assert_output(
        "x = {'one': 1, 'two': 2}\nfor key in x:\n    print(key)",
        &["one", "two"],
    );
}

// Adapted from CPython extended unpacking doctests in
// Lib/test/test_unpack_ex.py. MiniPython supports dict display unpacking from
// dict values, with later entries overriding earlier entries.
#[test]
fn cpython_dict_display_unpacking_subset() {
    assert_output(
        "kwds = {'z': 0, 'w': 12}\nprint({'x': 1, 'y': 2, **kwds})",
        &["{'x': 1, 'y': 2, 'z': 0, 'w': 12}"],
    );
    assert_output(
        "print({**{'x': 1}, 'y': 2, **{'z': 3}})",
        &["{'x': 1, 'y': 2, 'z': 3}"],
    );
    assert_output(
        "print({**{'x': 1}, 'y': 2, **{'x': 3}})",
        &["{'x': 3, 'y': 2}"],
    );
    assert_output("print({**{'x': 1}, **{'x': 3}, 'x': 4})", &["{'x': 4}"]);
    assert_output("print({**{}})", &["{}"]);
    assert_output(
        "flag = True\nleft = {1: 2}\nright = {3: 4}\nprint({**(left if flag else right)})",
        &["{1: 2}"],
    );
    assert_output("a = {}\nb = {**a}\nb[0] = 1\nprint(a, b)", &["{} {0: 1}"]);
    assert_output("print({0: 1, **{0: 2}, 0: 3, 0: 4})", &["{0: 4}"]);
    assert_error(
        "print({**1})",
        "runtime error: dict update source must be a dict, got 1",
    );
    assert_error(
        "print({**[]})",
        "runtime error: dict update source must be a dict, got []",
    );
    assert_output("print({**d for d in [{'x': 1}]})", &["{'x': 1}"]);
}

