#[test]
fn cpython_string_startswith_endswith_subset() {
    assert_output(
        "print('hello'.startswith('he'), 'hello'.startswith('hello'), 'hello'.startswith('hello world'), 'hello'.startswith(''), 'hello'.startswith('ello'))\nprint('hello'.startswith('ello', 1), 'hello'.startswith('o', 4), 'hello'.startswith('o', 5), 'hello'.startswith('', 5), 'hello'.startswith('lo', 6))\nprint('helloworld'.startswith('lowo', 3), 'helloworld'.startswith('lowo', 3, 7), 'helloworld'.startswith('lowo', 3, 6))\nprint('hello'.startswith('he', 0, -1), 'hello'.startswith('he', -53, -1), 'hello'.startswith('ello', -4), 'hello'.startswith('o', -1), 'hello'.startswith('', -3, -3))\nprint(''.startswith('', 0, 1), ''.startswith('', 1, 0))\nprint('hello'.startswith(('he', 'ha')), 'hello'.startswith(('lo', 'llo')), 'hello'.startswith(('hellox', 'hello')), 'hello'.startswith(()), 'hello'.startswith(('he', 'hel'), 0, 2))",
        &[
            "True True False True False",
            "True True False True False",
            "True True False",
            "True True True True True",
            "True False",
            "True False True False True",
        ],
    );
    assert_output(
        "print('hello'.endswith('lo'), 'hello'.endswith('he'), 'hello'.endswith(''), 'hello'.endswith('hello world'))\nprint('helloworld'.endswith('worl', 3, 9), 'helloworld'.endswith('world', 3, 12), 'helloworld'.endswith('lowo', 1, 7), 'helloworld'.endswith('lowo', 4, 7))\nprint('ab'.endswith('ab', 0, 1), 'ab'.endswith('ab', 0, 0), ''.endswith('', 0, 1), ''.endswith('', 1, 0))\nprint('hello'.endswith('lo', -2), 'hello'.endswith('he', -2), 'hello'.endswith('', -3, -3), 'helloworld'.endswith('world', -7, 12), 'helloworld'.endswith('lowo', -8, -3))\nprint('hello'.endswith(('he', 'ha')), 'hello'.endswith(('lo', 'llo')), 'hello'.endswith(('hellox', 'hello')), 'hello'.endswith(()), 'hello'.endswith(('he', 'hell'), 0, 4))",
        &[
            "True False True False",
            "True True True False",
            "False False True False",
            "True False True True True",
            "False True True False True",
        ],
    );
    assert_output(
        "for expr in [lambda: 'hello'.startswith(), lambda: 'hello'.startswith(42), lambda: 'hello'.startswith((42,)), lambda: 'hello'.endswith(), lambda: 'hello'.endswith(42), lambda: 'hello'.endswith((42,))]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_find, ::test_rfind, ::test_index, and
// ::test_rindex. MiniPython covers forward/reverse search, optional bounds,
// `None` defaults, empty needle behavior, Unicode character positions, and
