// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_splitlines. MiniPython covers CR/LF/CRLF,
// terminal-break behavior, keepends as positional or keyword, Unicode line
// separators, and representative TypeError paths.
#[test]
fn cpython_string_splitlines_subset() {
    assert_output(
        "print('abc\\ndef\\n\\rghi'.splitlines())\nprint('abc\\ndef\\n\\r\\nghi'.splitlines())\nprint('abc\\ndef\\r\\nghi'.splitlines())\nprint('abc\\ndef\\r\\nghi\\n'.splitlines())\nprint('abc\\ndef\\r\\nghi\\n\\r'.splitlines())",
        &[
            "['abc', 'def', '', 'ghi']",
            "['abc', 'def', '', 'ghi']",
            "['abc', 'def', 'ghi']",
            "['abc', 'def', 'ghi']",
            "['abc', 'def', 'ghi', '']",
        ],
    );
    assert_output(
        "print('\\nabc\\ndef\\r\\nghi\\n\\r'.splitlines())\nprint('\\nabc\\ndef\\r\\nghi\\n\\r'.splitlines(False))\nprint('\\nabc\\ndef\\r\\nghi\\n\\r'.splitlines(keepends=True))",
        &[
            "['', 'abc', 'def', 'ghi', '']",
            "['', 'abc', 'def', 'ghi', '']",
            "['\\n', 'abc\\n', 'def\\r\\n', 'ghi\\n', '\\r']",
        ],
    );
    assert_output(
        "print(''.splitlines(), 'one'.splitlines(), 'one\\n'.splitlines(), '\\n'.splitlines(), '\\r\\n'.splitlines())\nprint('a\\vb\\fc\\x1cd\\x1ee\\x85f\\u2028g\\u2029h'.splitlines())\nprint('a\\vb\\fc\\x1cd\\x1ee\\x85f\\u2028g\\u2029h'.splitlines(True) == ['a\\v', 'b\\f', 'c\\x1c', 'd\\x1e', 'e\\x85', 'f\\u2028', 'g\\u2029', 'h'])",
        &[
            "[] ['one'] ['one'] [''] ['']",
            "['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h']",
            "True",
        ],
    );
    assert_output(
        "for expr in [lambda: 'abc'.splitlines(True, False), lambda: 'abc'.splitlines(keepends=True, extra=False), lambda: 'abc'.splitlines(extra=True)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &["TypeError", "TypeError", "TypeError"],
    );
}

// Adapted from CPython's string method coverage in
