// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_replace. MiniPython covers empty-string
// insertion, deletion, left-to-right non-overlapping replacement, bounded
// counts, Unicode text, and representative TypeError paths.
#[test]
fn cpython_string_replace_subset() {
    assert_output(
        "print(repr(''.replace('', '')), repr(''.replace('', 'A')), repr(''.replace('A', '')), repr(''.replace('A', 'A')))\nprint(repr(''.replace('', '', 100)), repr(''.replace('', 'A', 100)), repr(''.replace('', '', 10 ** 30)))",
        &["'' 'A' '' ''", "'' 'A' ''"],
    );
    assert_output(
        "print('A'.replace('', ''), 'A'.replace('', '*'), 'A'.replace('', '*1'))\nprint('AA'.replace('', '*-', -1), 'AA'.replace('', '*-', 3), 'AA'.replace('', '*-', 2), 'AA'.replace('', '*-', 1), 'AA'.replace('', '*-', 0))\nprint('abc'.replace('', '-'), 'abc'.replace('', '-', 3), 'abc'.replace('', '-', 0))",
        &[
            "A *A* *1A*1",
            "*-A*-A*- *-A*-A*- *-A*-A *-AA AA",
            "-a-b-c- -a-b-c abc",
        ],
    );
    assert_output(
        "print(repr('AAA'.replace('A', '')), repr('AAA'.replace('A', '', 2)), repr('AAA'.replace('A', '', 1)), repr('AAA'.replace('A', '', 0)))\nprint('ABACADA'.replace('A', ''), 'ABACADA'.replace('A', '', 3), 'ABACADA'.replace('A', '', 2), 'ABACADA'.replace('A', '', 1))\nprint('here and there and there'.replace('the', ''), 'here and there and there'.replace('the', '', 2), 'here and there and there'.replace('the', '', 1))",
        &[
            "'' 'A' 'AA' 'AAA'",
            "BCD BCDA BCADA BACADA",
            "here and re and re here and re and re here and re and there",
        ],
    );
    assert_output(
        "print('Who goes there?'.replace('o', 'O', 2), 'Who goes there?'.replace('o', 'O', 1), 'Who goes there?'.replace('o', 'O', 0))\nprint('This is a tissue'.replace('is', '**', 2), 'This is a tissue'.replace('is', '**', 1))\nprint('Reykjavik'.replace('k', 'KK'), 'Reykjavik'.replace('k', 'KK', 1), '...м......<'.replace('<', '&lt;'))\nprint('spam, spam, eggs and spam'.replace('spam', 'ham', 2), 'one!two!three!'.replace('!', '@', 3), 'bobobob'.replace('bobob', 'bob'))",
        &[
            "WhO gOes there? WhO goes there? Who goes there?",
            "Th** ** a tissue Th** is a tissue",
            "ReyKKjaviKK ReyKKjavik ...м......&lt;",
            "ham, ham, eggs and spam one@two@three@ bobob",
        ],
    );
    assert_output(
        "for expr in [lambda: 'hello'.replace(), lambda: 'hello'.replace(42), lambda: 'hello'.replace(42, 'h'), lambda: 'hello'.replace('h', 42), lambda: 'hello'.replace('h', 'x', None), lambda: 'hello'.replace('h', 'x', 1, 2)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

