// Adapted from CPython's tokenizer behavior for explicit line joining inside
// string, bytes, and f-string literal text.
#[test]
fn cpython_string_line_continuation_subset() {
    assert_output(
        concat!("print('a\\\n", "b', \"c\\\r\n", "d\", '''e\\\n", "f''')"),
        &["ab cd ef"],
    );
    assert_output(concat!("print(r'a\\\n", "b')"), &["a\\\nb"]);
    assert_output(concat!("print(b'a\\\n", "b')"), &["b'ab'"]);
    assert_output(concat!("print(br'a\\\r\n", "b')"), &[r#"b'a\\\nb'"#]);
    assert_output(concat!("print(f'a\\\n", "{1}b')"), &["a1b"]);
    assert_output(concat!("print(repr(rf'a\\\n", "{1}b'))"), &[r#"'a\\\n1b'"#]);
}

// Adapted from CPython string escape coverage in
// Lib/test/test_string_literals.py. MiniPython accepts the same octal escape
// spellings for ordinary strings and models the tokenizer warning messages for
// invalid escape and out-of-byte-range octal escape sequences.
#[test]
fn cpython_string_octal_escape_subset() {
    assert_output(
        r#"print('\1' == '\x01', '\01' == '\x01', '\001' == '\x01')"#,
        &["True True True"],
    );
    assert_output(
        r#"print('\377' == '\u00ff', '\400' == '\u0100', '\777' == '\u01ff')"#,
        &["True True True"],
    );
}

#[test]
fn cpython_string_escape_warning_subset() {
    let invalid_escape = invalid_escape_warning('z');
    let invalid_octal = r#""\400" is an invalid octal escape sequence. Such sequences will not work in the future. Did you mean "\\400"? A raw string is also an option."#;
    let invalid_byte_octal = r#""\407" is an invalid octal escape sequence. Such sequences will not work in the future. Did you mean "\\407"? A raw string is also an option."#;

    assert_warnings(r#"'\z'"#, &[&invalid_escape]);
    assert_warnings(r#"b'\z'"#, &[&invalid_escape]);
    assert_warnings(r#"'\400'"#, &[invalid_octal]);
    assert_warnings(r#"b'\407'"#, &[invalid_byte_octal]);
    assert_warnings(r#"r'\z' br'\407'"#, &[]);
    assert_warnings(r#"'\z' '\400'"#, &[&invalid_escape, invalid_octal]);

    assert_warning_as_error(r#"'\z'"#, &invalid_escape);
    assert_warning_as_error(r#"'\400'"#, invalid_octal);
    assert_eq!(
        run_source_with_warnings_as_errors(r#"r'\z'"#),
        Ok(Vec::new())
    );
}

// Adapted from CPython's
// Lib/test/test_string_literals.py::test_eval_str_invalid_escape and
// ::test_eval_bytes_invalid_escape ASCII loops. MiniPython uses the same warning
// text for every currently invalid one-character escape in ordinary strings and
// bytes literals.
#[test]
fn cpython_string_invalid_escape_ascii_table_subset() {
    fn assert_invalid_escape_table(prefix: &str, valid_escape_chars: &str) {
        for byte in 1u8..=127 {
            let ch = byte as char;
            if valid_escape_chars.contains(ch) {
                continue;
            }

            let source = format!("{prefix}'\\{ch}'");
            let expected = invalid_escape_warning(ch);
            assert_warnings(&source, &[&expected]);
            assert_warning_as_error(&source, &expected);
        }
    }

    assert_invalid_escape_table("", "\n\r\"'01234567NU\\abfnrtuvx");
    assert_invalid_escape_table("b", "\n\r\"'01234567\\abfnrtvx");
}

// Adapted from CPython's
// Lib/test/test_string_literals.py::test_eval_str_invalid_escape and
// ::test_eval_str_invalid_octal_escape warning metadata assertions. MiniPython
// records the warning category and 1-based source location in its lightweight
// lexer diagnostic API.
#[test]
fn cpython_string_escape_warning_location_subset() {
    let invalid_escape = r#""\z" is an invalid escape sequence. Such sequences will not work in the future. Did you mean "\\z"? A raw string is also an option."#;
    let invalid_octal = r#""\407" is an invalid octal escape sequence. Such sequences will not work in the future. Did you mean "\\407"? A raw string is also an option."#;
    let invalid_space = r#""\ " is an invalid escape sequence. Such sequences will not work in the future. Did you mean "\\ "? A raw string is also an option."#;

    assert_warning_diagnostic("'''\n\\z'''", invalid_escape, 2, 1, 2, 3);
    assert_warning_diagnostic("b'''\n\\407'''", invalid_octal, 2, 1, 2, 5);
    assert_warning_diagnostic("\"''Incorrect \\ logic?\"", invalid_space, 1, 14, 1, 16);
    assert_warning_as_error_diagnostic("'''\n\\z'''", invalid_escape, 2, 1, 2, 3);
    assert_warning_as_error_diagnostic("b'''\n\\407'''", invalid_octal, 2, 1, 2, 5);
}

// Adapted from CPython's
// Lib/test/test_fstring.py::test_backslashes_in_string_part and
// ::test_fstring_backslash_before_double_bracket. MiniPython keeps the same
// executable result for backslash-plus-brace f-string literal text and records
// the warning text through its lightweight lexer warning API.
#[test]
fn cpython_f_string_escape_warning_subset() {
    let invalid_g = r#""\g" is an invalid escape sequence. Such sequences will not work in the future. Did you mean "\\g"? A raw string is also an option."#;
    let invalid_left_brace = r#""\{" is an invalid escape sequence. Such sequences will not work in the future. Did you mean "\\{"? A raw string is also an option."#;
    let invalid_right_brace = r#""\}" is an invalid escape sequence. Such sequences will not work in the future. Did you mean "\\}"? A raw string is also an option."#;

    assert_output(r#"print(f'\{6*7}', f'\g')"#, &[r"\42 \g"]);
    assert_warnings(r#"f'\{6*7}'"#, &[invalid_left_brace]);
    assert_warnings(r#"f'\g'"#, &[invalid_g]);
    assert_warnings(r#"f'\{{'"#, &[invalid_left_brace]);
    assert_warnings(r#"f'\{{\}}'"#, &[invalid_left_brace, invalid_right_brace]);
    assert_warnings(r#"fr'\{{' rf'\g'"#, &[]);

    assert_warning_as_error(r#"f'\g'"#, invalid_g);
    assert_warning_as_error_diagnostic(r#"f'\g'"#, invalid_g, 1, 3, 1, 5);
}

// Adapted from CPython string-literal and f-string Unicode-name escape coverage
// in Lib/test/test_string_literals.py and Lib/test/test_fstring.py.
#[test]
fn cpython_unicode_name_escape_subset() {
    assert_output(
        r#"print('\N{LATIN CAPITAL LETTER A}', '\N{latin small letter a with diaeresis}')"#,
        &["A ä"],
    );
    assert_output(
        r#"print(u'\N{LATIN SMALL LETTER A WITH DIAERESIS}')"#,
        &["ä"],
    );
    assert_output(
        r#"print(r'\N{LATIN CAPITAL LETTER A}')"#,
        &[r#"\N{LATIN CAPITAL LETTER A}"#],
    );
    assert_output(r#"print(f'2\N{GREEK CAPITAL LETTER DELTA}3')"#, &["2Δ3"]);
    assert_output(
        r#"print(f'\N{LEFT CURLY BRACKET}1+1\N{RIGHT CURLY BRACKET}')"#,
        &["{1+1}"],
    );
    assert_output(r#"print(t'\N{AMPERSAND}'.strings)"#, &["('&',)"]);
    assert_output(
        r#"print('\N{LF}' == '\n', '\N{line feed}' == '\n', '\N{NEW LINE}' == '\n')"#,
        &["True True True"],
    );
    assert_output(
        r#"print('\N{NUL}' == '\x00', '\N{BOM}' == '\ufeff', '\N{BACKSPACE}' == '\b')"#,
        &["True True True"],
    );
    assert_output(r#"print(f'{1}\N{LF}{2}' == '1\n2')"#, &["True"]);
    assert_output(r#"print(t'\N{BOM}'.strings == ('\ufeff',))"#, &["True"]);

    assert_error(
        r#"print('\N')"#,
        "lex error: malformed Unicode name escape: \\N",
    );
    assert_error(
        r#"print('\N{')"#,
        "lex error: malformed Unicode name escape: \\N",
    );
    assert_error(
        r#"print('\N{bad}')"#,
        "lex error: unknown Unicode character name: bad",
    );
    assert_error(
        r#"print('\N{LATIN_CAPITAL_LETTER_A}')"#,
        "lex error: unknown Unicode character name: LATIN_CAPITAL_LETTER_A",
    );
    assert_error(
        r#"print('\N{NEW_LINE}')"#,
        "lex error: unknown Unicode character name: NEW_LINE",
    );
    assert_error(
        r#"print('\N{LINE    FEED}')"#,
        "lex error: unknown Unicode character name: LINE    FEED",
    );
    assert_error(
        r#"print('\N{linefeed}')"#,
        "lex error: unknown Unicode character name: linefeed",
    );
}

// Adapted from CPython bytes literal tokenization in
// Lib/test/test_tokenize.py, bytes repr/concat/compare coverage in
// Lib/test/test_bytes.py, and bytes constants in Lib/test/test_ast/test_ast.py.
#[test]
fn cpython_bytes_literal_subset() {
    assert_output("print(b'abc', B\"abc\")", &["b'abc' b'abc'"]);
    assert_output(
        "print(br'\\n', bR'\\n', Rb'\\n', RB'\\n')",
        &["b'\\\\n' b'\\\\n' b'\\\\n' b'\\\\n'"],
    );
    assert_output("print(b'a' b'b' b'c')", &["b'abc'"]);
    assert_output("print(b'\\x41\\n\\377')", &["b'A\\n\\xff'"]);
    assert_output("print(len(b'abc'), b'abc'[0], b'abc'[1:])", &["3 97 b'bc'"]);
    assert_output("print(b'ab' + b'cd', b'ab' * 2)", &["b'abcd' b'abab'"]);
    assert_output(
        "print(b'a' == b'a', b'a' != b'b', b'a' == 'a')",
        &["True True False"],
    );
    assert_output(
        "print(bytes(), bytes(3), bytes(b'abc'))",
        &["b'' b'\\x00\\x00\\x00' b'abc'"],
    );
    assert_error(
        "print(b'a' 'b')",
        "parse error: cannot mix bytes and nonbytes literals",
    );
    assert_error(
        "print('a' b'b')",
        "parse error: cannot mix bytes and nonbytes literals",
    );
}

// Adapted from CPython's dynamic string prefix check in
// Lib/test/test_tokenize.py::StringPrefixTest and prefix smoke coverage in
// Lib/test/test_grammar.py::test_string_prefixes / ::test_bytes_prefixes.
#[test]
fn cpython_string_prefix_matrix_subset() {
    assert_output("print(u'abc', U\"abc\")", &["abc abc"]);
    assert_output("print(r'abc\\t', R\"abc\\t\")", &["abc\\t abc\\t"]);
    assert_output("print(f'abc {1 + 1}', F\"abc {1 + 1}\")", &["abc 2 abc 2"]);
    assert_output(
        "print(rf'abc\\t {1 + 1}', Fr\"abc\\t {1 + 1}\")",
        &["abc\\t 2 abc\\t 2"],
    );
    assert_output(
        "print(t'abc')",
        &["Template(strings=('abc',), interpolations=())"],
    );
    assert_output(
        "print(tr'abc\\t'.strings, Rt\"abc\\t\".strings)",
        &["('abc\\\\t',) ('abc\\\\t',)"],
    );
    assert_output(
        "print(b'abc', B\"abc\", br'abc\\t', rB\"abc\\t\")",
        &["b'abc' b'abc' b'abc\\\\t' b'abc\\\\t'"],
    );

    for prefix in [
        "ur", "ru", "bf", "fb", "bt", "tb", "uf", "fu", "ut", "tu", "ft", "tf", "bu", "ub", "rr",
        "ff", "bb", "tt",
    ] {
        assert_rejected(&format!("print({prefix}'abc')"));
    }
}

// Adapted from CPython Lib/test/test_fstring.py::test_invalid_string_prefixes.
// These spellings look like string prefixes, but combine mutually incompatible
// prefix families.
#[test]
fn cpython_invalid_string_prefix_matrix_subset() {
    let single_quote_cases = [
        "fu''", "uf''", "Fu''", "fU''", "Uf''", "uF''", "ufr''", "urf''", "fur''", "fru''",
        "rfu''", "ruf''", "FUR''", "Fur''", "fb''", "fB''", "Fb''", "FB''", "bf''", "bF''", "Bf''",
        "BF''",
    ];

    for source in single_quote_cases {
        assert_error(source, "lex error: prefixes are incompatible");
    }

    for source in single_quote_cases.map(|source| source.replace('\'', "\"")) {
        assert_error(&source, "lex error: prefixes are incompatible");
    }

    assert_lex_error_diagnostic("FUR''", "prefixes are incompatible", 1, 1, 1, 4);
}

// Adapted from CPython SyntaxError coverage for unterminated strings in
// Lib/test/test_syntax.py::test_error_string_literal and tokenizer escape
// errors for malformed string and bytes escapes.
#[test]
fn cpython_invalid_string_literal_subset() {
    assert_error("'blech", "lex error: unterminated string literal");
    assert_error("'sdfsdf", "lex error: unterminated string literal");
    assert_error("\"blech", "lex error: unterminated string literal");
    assert_error(
        "\"blech\\\"",
        "lex error: unterminated string literal; perhaps you escaped the end quote",
    );
    assert_error(
        "r\"blech\\\"",
        "lex error: unterminated string literal; perhaps you escaped the end quote",
    );
    assert_error(
        "'''blech",
        "lex error: unterminated triple-quoted string literal",
    );
    assert_error(
        "'''sdfsdf''",
        "lex error: unterminated triple-quoted string literal",
    );
    assert_error(
        "\"\"\"blech",
        "lex error: unterminated triple-quoted string literal",
    );
    assert_error(
        "\"\"\"blech\nsecond",
        "lex error: unterminated triple-quoted string literal",
    );
    assert_error(
        "b'''blech",
        "lex error: unterminated triple-quoted string literal",
    );
    assert_error("b\"bytes", "lex error: unterminated string literal");

    assert_lex_error_diagnostic("'blech", "unterminated string literal", 1, 1, 1, 7);
    assert_lex_error_diagnostic("'sdfsdf", "unterminated string literal", 1, 1, 1, 8);
    assert_lex_error_diagnostic("\"blech", "unterminated string literal", 1, 1, 1, 7);
    assert_lex_error_diagnostic(
        "\"blech\\\"",
        "unterminated string literal; perhaps you escaped the end quote",
        1,
        1,
        1,
        9,
    );
    assert_lex_error_diagnostic(
        "r\"blech\\\"",
        "unterminated string literal; perhaps you escaped the end quote",
        1,
        1,
        1,
        10,
    );
    assert_lex_error_diagnostic(
        "'''blech",
        "unterminated triple-quoted string literal",
        1,
        1,
        1,
        9,
    );
    assert_lex_error_diagnostic(
        "'''sdfsdf''",
        "unterminated triple-quoted string literal",
        1,
        1,
        1,
        12,
    );
    assert_lex_error_diagnostic(
        "\"\"\"blech",
        "unterminated triple-quoted string literal",
        1,
        1,
        1,
        9,
    );
    assert_lex_error_diagnostic(
        "\"\"\"blech\nsecond",
        "unterminated triple-quoted string literal",
        1,
        1,
        2,
        7,
    );
    assert_lex_error_diagnostic(
        "b'''blech",
        "unterminated triple-quoted string literal",
        1,
        1,
        1,
        10,
    );
    assert_lex_error_diagnostic("b\"bytes", "unterminated string literal", 1, 1, 1, 8);
    assert_lex_error_diagnostic("'a\nprint(1)", "unterminated string literal", 1, 1, 1, 3);

    assert_error(r#"print('\x')"#, "lex error: truncated string escape: \\x");
    assert_error(
        r#"print('\x0g')"#,
        "lex error: invalid string escape: \\x0g",
    );
    assert_error(
        r#"print('\u123')"#,
        "lex error: truncated string escape: \\u",
    );
    assert_error(
        r#"print('\u12x4')"#,
        "lex error: invalid string escape: \\u12x4",
    );
    assert_error(
        r#"print('\U00110000')"#,
        "lex error: invalid string escape: \\U00110000",
    );
    assert_error(r#"print(b'\x')"#, "lex error: invalid bytes escape: \\x");
    assert_error(
        r#"print(b'\x0g')"#,
        "lex error: invalid bytes escape: \\x0g",
    );
    assert_error(
        "print(b'caf\u{e9}')",
        "lex error: bytes can only contain ASCII literal characters",
    );
    assert_lex_error_diagnostic(
        "print(b'caf\u{e9}')",
        "bytes can only contain ASCII literal characters",
        1,
        7,
        1,
        14,
    );
    assert_lex_error_diagnostic(
        "b\"abc \u{44a}\u{44e}\u{449}\u{44b}\u{439}\"",
        "bytes can only contain ASCII literal characters",
        1,
        1,
        1,
        13,
    );
}

