// Adapted from CPython-only SyntaxErrorTestCase static nesting and parser
// complexity checks:
// - test_nested_named_except_blocks
// - test_with_statement_many_context_managers
// - test_async_with_statement_many_context_managers
// - test_syntax_error_on_deeply_nested_blocks
// - test_error_on_parser_stack_overflow
// - test_deep_invalid_rule
#[test]
fn cpython_static_nesting_and_complexity_limit_subset() {
    assert_output(&nested_while_source(21), &[]);
    assert_error(
        &nested_while_source(22),
        "compile error: too many statically nested blocks",
    );

    assert_output(&nested_named_except_source(10), &[]);
    assert_error(
        &nested_named_except_source(12),
        "compile error: too many statically nested blocks",
    );

    assert_output(&many_context_managers_source(false, 19), &[]);
    assert_error(
        &many_context_managers_source(false, 20),
        "compile error: too many statically nested blocks",
    );
    assert_output(&many_context_managers_source(true, 19), &[]);
    assert_error(
        &many_context_managers_source(true, 20),
        "compile error: too many statically nested blocks",
    );

    let deep_unary = format!("{}4", "-".repeat(100_000));
    assert_error_contains(&deep_unary, "too complex");
    let eval_error = eval_source(&deep_unary).expect_err("deep eval input should fail");
    assert!(eval_error.contains("too complex"), "error: {eval_error}");
    let interactive_error =
        run_interactive_source(&deep_unary).expect_err("deep interactive input should fail");
    assert!(
        interactive_error.contains("too complex"),
        "error: {interactive_error}"
    );

    assert_rejected("d{{{{{{{{{{{{{{{{{{{{{{{{{```{{{{{{{ef f():y");
}

fn nested_while_source(depth: usize) -> String {
    let mut source = String::new();
    for level in 0..depth {
        source.push_str(&" ".repeat(level));
        source.push_str("while 0:\n");
    }
    source.push_str(&" ".repeat(depth));
    source.push_str("pass\n");
    source
}

fn nested_named_except_source(depth: usize) -> String {
    let mut source = String::from("def f():\n");
    for level in 0..depth {
        let indent = "    ".repeat(level + 1);
        let body_indent = "    ".repeat(level + 2);
        source.push_str(&indent);
        source.push_str("try:\n");
        source.push_str(&body_indent);
        source.push_str("raise Exception\n");
        source.push_str(&indent);
        source.push_str("except Exception as e:\n");
    }
    source.push_str(&"    ".repeat(depth + 1));
    source.push_str("pass\n");
    source
}

fn many_context_managers_source(is_async: bool, extra_managers: usize) -> String {
    let mut source = if is_async {
        "async def bug():\n    async with (\n    a\n".to_string()
    } else {
        "def bug():\n    with (\n    a\n".to_string()
    };
    for index in 0..extra_managers {
        source.push_str(&format!("    as a{index}, a\n"));
    }
    source.push_str("): yield a");
    source
}

// Adapted from CPython f-string coverage in
// Lib/test/test_fstring.py::test_literal, ::test_double_braces,
// ::test_compile_time_concat, ::test_equal_equal, ::test_conversions, and
// ::test_backslashes_in_expression_part / ::test_no_escapes_for_braces /
// ::test_newlines_in_expressions / ::test_comments / ::test_lambda /
// ::test_valid_prefixes / ::test_roundtrip_raw_quotes /
// ::test_fstring_backslash_before_double_bracket.
// MiniPython supports basic f-string literal parts, replacement expressions,
// format-spec width/precision/alignment, dynamic width fields, and
// `!s`/`!r`/`!a` conversions. Escaped braces become literal text and do not
// start or end replacement fields; replacement expressions use ordinary Python
// string-escape rules independently of the outer f-string prefix, and multiline
// replacement expressions are parsed as ordinary expression source.
#[test]
fn cpython_f_string_basic_subset() {
    assert_output("print(f'')", &[""]);
    assert_output("print(f'a')", &["a"]);
    assert_output("print(F'{1}', FR'{2}', fR'{3}')", &["1 2 3"]);
    assert_output(
        r#"print(f'\\', f'\\\\')
print(fr'\\', fr'\\\\')
print(rf'\\', rf'\\\\')
print(Rf'\\', Rf'\\\\')
print(fR'\\', fR'\\\\')
print(FR'\\', FR'\\\\')"#,
        &[
            r"\ \\", r"\\ \\\\", r"\\ \\\\", r"\\ \\\\", r"\\ \\\\", r"\\ \\\\",
        ],
    );
    assert_output("x = 'def'\nprint('abc' f'{x}' 'ghi')", &["abcdefghi"]);
    assert_output(
        "print(f'{{', f'}}', f'{{{10}', f'{10}}}')",
        &["{ } {10 10}"],
    );
    assert_output(r#"print(f'\x7b1+1}}')"#, &["{1+1}"]);
    assert_output(r#"print(f'\x7b1+1')"#, &["{1+1"]);
    assert_output(r#"print(f'\u007b1+1')"#, &["{1+1"]);
    assert_output(
        r#"print(f'\N{LEFT CURLY BRACKET}1+1\N{RIGHT CURLY BRACKET}')"#,
        &["{1+1}"],
    );
    assert_output("print(f\"{(\n    1 +\n    2\n)}\")", &["3"]);
    assert_output("print(f'{0}', rf'''{3+\n4}''')", &["0 7"]);
    assert_output(
        r#"print(f'{"\N{LEFT CURLY BRACKET}"}', rf'{"\N{LEFT CURLY BRACKET}"}')"#,
        &["{ {"],
    );
    assert_output(
        "x = 5\nprint(f'{(lambda y:x*y)(\"8\")!r}')\nprint(f'{(lambda y:x*y)(\"8\")!r:10}')\nprint(f'{(lambda y:x*y)(\"8\"):10}')",
        &["'88888'", "'88888'   ", "88888     "],
    );
    assert_output(
        r###"print(fr"\'")
print(fr'\"')
print(fr'\"\'')
print(fr'\'\"')
print(fr'\"\'\"')
print(fr'\'\"\'')
print(fr'\"\'\"\'')"###,
        &[
            r"\'",
            r#"\""#,
            r#"\"\'"#,
            r#"\'\""#,
            r#"\"\'\""#,
            r#"\'\"\'"#,
            r#"\"\'\"\'"#,
        ],
    );
    assert_output(
        r#"print(f'\{{\}}')
print(f'\{{')
print(f'\{{{1+1}')
print(f'\}}{1+1}')
print(f'{1+1}\}}')
print(fr'\{{\}}')
print(fr'\{{')
print(fr'\{{{1+1}')
print(fr'\}}{1+1}')
print(fr'{1+1}\}}')"#,
        &[
            r"\{\}", r"\{", r"\{2", r"\}2", r"2\}", r"\{\}", r"\{", r"\{2", r"\}2", r"2\}",
        ],
    );
    assert_output("print(f'{0==1}', f'{3!=4}', f'{3!s  }')", &["False True 3"]);
    assert_output(r#"print(f'{"a"}', f'{"a"!r}', f'{"a"!a}')"#, &["a 'a' 'a'"]);
    assert_output("x = 'test'\nprint(f'{x:}')", &["test"]);
    assert_output(
        "print(f'{3:4}', f'{1.25:.2f}', f'{3.14:!<10.10}')",
        &["   3 1.25 3.14!!!!!!"],
    );
    assert_output(
        "x = 'test'\nprint(f'{x!r:^10}', f'{x!s:.2}')",
        &["  'test'   te"],
    );
    assert_output(
        "print(f'{3.14:10.10}', f'{1.25!s:10.10}', f'{3!s  :4}')",
        &["      3.14 1.25       3   "],
    );
    assert_output("width = 4\nprint(f'{3:{width}}')", &["   3"]);
    assert_output(
        "print(f'{1:}}}', f'{1:>3{5}}}}')",
        &["1}                                   1}"],
    );
    assert_output("print(f'{10:x}', f'{10:X}')", &["a A"]);
    assert_output(
        "d = {'#': 'hash'}\nprint(f'{\"#\"}', f'{d[\"#\"]}')",
        &["# hash"],
    );
    assert_output(
        "print(f'''A complex trick: {\n2 # two\n}''')",
        &["A complex trick: 2"],
    );
    assert_output(
        "print(f'''{\n40 # forty\n+  # plus\n2  # two\n}''')",
        &["42"],
    );
    assert_output(
        "print(f'{\"\"\"# this is not a comment\n        a\"\"\" # this is a comment\n        }')",
        &["# this is not a comment\n        a"],
    );
    assert_output("print(f\"\"\"{f'''{f'{f\"{1+1}\"}'}'''}\"\"\")", &["2"]);
    assert_output(
        "print(f'''\n# this is not a comment\n{ # the following operation it's\n3 # this is a number\n* 2}''')",
        &["\n# this is not a comment\n6"],
    );
    assert_output(
        "print(f'''\n{# f'a {comment}'\n86 # constant\n# nothing more\n}''')",
        &["\n86"],
    );
}

// Adapted from CPython Lib/test/test_fstring.py::test_not_equal,
// ::test_equal_equal, and the conversion/formatting portions of
// ::test_conversions. These cases pin down the f-string parser distinction
// between `!=` as part of the expression, `!` as conversion syntax, and `=`
// as debug-expression syntax.
#[test]
fn cpython_f_string_conversion_operator_edge_subset() {
    assert_output(
        "print(f'{3!=4}', f'{3!=4:}', f'{3!=4!s}', f'{3!=4!s:.3}')",
        &["True True True Tru"],
    );
    assert_output("print(f'{0==1}')", &["False"]);
    assert_output(
        "print(f'{3.14:10.10}', f'{1.25!s:10.10}', f'{1.25!r:10.10}', f'{1.25!a:10.10}')",
        &["      3.14 1.25       1.25       1.25      "],
    );
    assert_output(
        r#"print(f'{"a"}', f'{"a"!r}', f'{"a"!a}', f'{"a!r"}')"#,
        &["a 'a' 'a' a!r"],
    );
    assert_output("print(f'{3!s  }', f'{1.25!s  :10.10}')", &["3 1.25      "]);
    assert_output("print(f'{3.14:!<10.10}')", &["3.14!!!!!!"]);

    for source in [
        "print(f'{3!g}')",
        "print(f'{3!A}')",
        "print(f'{3!G}')",
        "print(f'{3!ä}')",
        "print(f'{3!ɐ}')",
    ] {
        assert_rejected(source);
    }
}

// Adapted from CPython Lib/test/test_fstring.py::test_if_conditional,
// ::test_empty_format_specifier, ::test_str_format_differences, ::test_loop,
// and ::test_dict. This covers f-strings in truth-value positions, empty
// format specs, the difference between f-string expression indexing and
// `str.format()` field-name indexing, repeated loop evaluation, and nested
// quote handling in f-string dictionary subscripts.
#[test]
fn cpython_f_string_contextual_runtime_subset() {
    assert_output(
        "x = ''\nif f'{x}':\n    print(1)\nelse:\n    print(2)\nx = ' '\nif '' f'{x}':\n    print(1)\nelse:\n    print(2)\nx = ''\nif ' ' f'{x}':\n    print(1)\nelse:\n    print(2)",
        &["2", "1", "1"],
    );
    assert_output(
        "x = 'test'\nprint(f'{x}', f'{x:}', f'{x!s:}', f'{x!r:}')",
        &["test test test 'test'"],
    );
    assert_output(
        "d = {'a': 'string', 0: 'integer'}\na = 0\nprint(f'{d[0]}', f'{d[\"a\"]}', f'{d[a]}')\nprint('{d[a]}'.format(d=d), '{d[0]}'.format(d=d))",
        &["integer string integer", "string integer"],
    );
    assert_output(
        "text = ''\nfor i in range(5):\n    text = text + f'i:{i};'\nprint(text)",
        &["i:0;i:1;i:2;i:3;i:4;"],
    );
    assert_output(
        "d = {'\"': 'dquote', \"'\": 'squote', 'foo': 'bar'}\nprint(f'''{d[\"'\"]}''', f\"\"\"{d['\\\"']}\"\"\", f'{d[\"foo\"]}', f\"{d['foo']}\")",
        &["squote dquote bar bar"],
    );
}

// Adapted from CPython Lib/test/test_fstring.py::test_multiple_vars,
// ::test_closure, ::test_arguments, ::test_locals, ::test_missing_variable,
// and ::test_missing_format_spec. These cases keep f-string name resolution
// aligned across local variables, closures, globals used by function bodies,
// format-spec expressions, and missing-name failures.
#[test]
fn cpython_f_string_scope_and_format_lookup_subset() {
    assert_output(
        "x = 98\ny = 'abc'\nprint(f'{x}{y}')\nprint(f'X{x}{y}')\nprint(f'{x}X{y}')\nprint(f'{x}{y}X')\nprint(f'X{x}Y{y}')\nprint(f'X{x}{y}Y')\nprint(f'{x}X{y}Y')\nprint(f'X{x}Y{y}Z')",
        &[
            "98abc", "X98abc", "98Xabc", "98abcX", "X98Yabc", "X98abcY", "98XabcY", "X98YabcZ",
        ],
    );
    assert_output(
        "def outer(x):\n    def inner():\n        return f'x:{x}'\n    return inner\nprint(outer('987')())\nprint(outer(7)())",
        &["x:987", "x:7"],
    );
    assert_output(
        "y = 2\ndef f(x, width):\n    return f'x={x*y:{width}}'\nprint(f('foo', 10))\nx = 'bar'\nprint(f(10, 10))",
        &["x=foofoo    ", "x=        20"],
    );
    assert_output("value = 123\nprint(f'v:{value}')", &["v:123"]);
    assert_error(
        "print(f'v:{value}')",
        "runtime error: NameError: unknown name: value",
    );
    assert_output(
        "class O:\n    def __format__(self, spec):\n        if not spec:\n            return '*'\n        return spec\nprint(f'{O():x}', f'{O()}')",
        &["x *"],
    );
}

// Adapted from CPython Lib/test/test_fstring.py::test_errors. This keeps
// f-string formatting failures aligned with CPython's exception classes and
// messages for unsupported object format specs and unknown integer format
// codes.
#[test]
fn cpython_f_string_format_error_subset() {
    assert_error(
        "print(f'{(lambda: 0):x}')",
        "runtime error: TypeError: unsupported format string passed to function.__format__",
    );
    assert_error(
        "print(f'{(0,):x}')",
        "runtime error: TypeError: unsupported format string passed to tuple.__format__",
    );
    assert_error(
        "print(f'{1000:j}')",
        "runtime error: ValueError: Unknown format code 'j' for object of type 'int'",
    );
}

// Adapted from CPython's Lib/test/test_fstring.py::test_many_expressions.
// The original assertions compare the full rendered strings; MiniPython checks
// lengths to keep the Rust test output compact while preserving the same
// f-string part-count, adjacent f-string, and adjacent string-concatenation
// semantics.
#[test]
fn cpython_f_string_many_expressions_subset() {
    fn build_fstr(n: usize, extra: &str) -> String {
        format!("f'{}{}'", "{x} ".repeat(n), extra)
    }

    for count in 250..260 {
        let source = format!("x = 'X'\nprint(len({}))", build_fstr(count, ""));
        let expected = (count * 2).to_string();
        assert_output(&source, &[expected.as_str()]);
    }

    let adjacent_fstrings = build_fstr(255, "").repeat(256);
    let source = format!("x = 'X'\nprint(len({adjacent_fstrings}))");
    let expected = (255 * 2 * 256).to_string();
    assert_output(&source, &[expected.as_str()]);

    let source = format!(
        "x = 'X'\nwidth = 1\nprint(len({}))",
        build_fstr(253, "{x:{width}} ")
    );
    let expected = (254 * 2).to_string();
    assert_output(&source, &[expected.as_str()]);

    let adjacent_with_plain_strings = "f'{1}' 'x' 'y'".repeat(1024);
    let source = format!("print(len({adjacent_with_plain_strings}))");
    let expected = (3 * 1024).to_string();
    assert_output(&source, &[expected.as_str()]);
}

// Adapted from CPython's
// Lib/test/test_fstring.py::test_debug_conversion and ::test_gh129093.
// MiniPython preserves the debug label text and covers default repr,
// whitespace around the debug `=`, explicit conversions, conversion
// formatting, nested f-strings, comparison operators before the debug `=`,
// and simple format specs.
#[test]
fn cpython_f_string_debug_expression_subset() {
    assert_output(
        "x = 'A string'\nprint(f'{x=}')\nprint(f'{x =}')\nprint(f'{x=!s}', f'{x=!r}', f'{x=!a}')",
        &[
            "x='A string'",
            "x ='A string'",
            "x=A string x='A string' x='A string'",
        ],
    );
    assert_output("x = 9\nprint(f'{3*x+15=}')", &["3*x+15=42"]);
    assert_output(
        "x = 2.71828\nprint(f'{x=:.2f}', f'{x=:}')",
        &["x=2.72 x=2.71828"],
    );
    assert_output(
        "x = 'A string'\nprint(f'X{x  =}Y')\nprint(f'X{x=  }Y')\nprint(f'X{x  =  }Y')\nprint(f'{x = !s}')",
        &[
            "Xx  ='A string'Y",
            "Xx=  'A string'Y",
            "Xx  =  'A string'Y",
            "x = A string",
        ],
    );
    assert_output("print(f\"{1+2 = # my comment\n  }\")", &["1+2 = \n  3"]);
    assert_output(
        "print(f'{ # some comment goes here\n  \"\"\"hello\"\"\"=}')",
        &[" \n  \"\"\"hello\"\"\"='hello'"],
    );
    assert_output(
        "x = 2.71828\nprint(f'{x=!r:^20}')\nprint(f'{x=!s:^20}')\nprint(f'{x=!a:^20}')",
        &[
            "x=      2.71828       ",
            "x=      2.71828       ",
            "x=      2.71828       ",
        ],
    );
    assert_output(
        r#"print(f'{f"{3.1415=:.1f}":*^20}')
print(f'sadsd {1 + 1 =  :{1 + 1:1d}f}')"#,
        &["*****3.1415=3.1*****", "sadsd 1 + 1 =  2.000000"],
    );
    assert_output(
        r#"print(f'{r"\xff"=}')
print(f'{r"\n"=}')
print(f'{b"\N{OX}"=}')"#,
        &[
            r#"r"\xff"='\\xff'"#,
            r#"r"\n"='\\n'"#,
            r#"b"\N{OX}"=b'\\N{OX}'"#,
        ],
    );
    assert_output(
        r#"print(f"{'\''=}")
print(f"{'\xc5'=}")"#,
        &["'\\''=\"'\"", r#"'\xc5'='Å'"#],
    );
    assert_output(
        "x = 20\nprint(f'{x:=10}')\nprint(x)\nprint(f'{(x:=10)}')\nprint(x)",
        &["        20", "20", "10", "10"],
    );
    assert_output(
        r#"print(f'{1==2=}')
print(f'{1 == 2=}')
print(f'{1!=2=}')
print(f'{1 != 2=}')
print(f'{(1) != 2=}')
print(f'{(1*2) != (3)=}')
print(f'{1 != 2 == 3 != 4=}')
print(f'{1 == 2 != 3 == 4=}')
print(f"{f'{1==2=}'=}")
print(f"{f'{1 != 2=}'=}")"#,
        &[
            "1==2=False",
            "1 == 2=False",
            "1!=2=True",
            "1 != 2=True",
            "(1) != 2=True",
            "(1*2) != (3)=True",
            "1 != 2 == 3 != 4=False",
            "1 == 2 != 3 == 4=False",
            "f'{1==2=}'='1==2=False'",
            "f'{1 != 2=}'='1 != 2=True'",
        ],
    );
}

