// literal middles, annotated_rhs replacement expressions, debug fields,
// conversions, empty/full format specs, and nested replacement fields.
#[test]
fn cpython_f_string_helper_rules_subset() {
    assert_output(
        "name = 'Mini'\nwidth = 6\nprec = 2\nvalue = 3.14159\nprint(f'plain middle')\nprint(f'Hello {name!s}')\nprint(f'{value:{width}.{prec}f}')\nprint(f'{name=!r:^10}')",
        &["plain middle", "Hello Mini", "  3.14", "name=  'Mini'  "],
    );
    assert_output(
        "def g():\n    rendered = f'{yield \"need\"!s:^6}'\n    yield rendered\ngen = g()\nprint(next(gen))\nprint(gen.send('ok'))",
        &["need", "  ok  "],
    );
}

