// Adapted from Lib/test/test_fstring.py::test_custom_format_specifier,
// ::test_side_effect_order, ::test__format__lookup, and
// Lib/test/test_builtin.py::test_format. This keeps the CPython rule that
// formatting looks up `__format__` on the class, while ordinary attribute access
// can still see an instance attribute with the same name.
#[test]
fn cpython_format_builtin_and_custom_dunder_format_subset() {
    assert_output(
        "print(format(3, ''), format('x'), format(1.25, '.1f'))",
        &["3 x 1.2"],
    );
    assert_output(
        "class CustomFormat:\n    def __format__(self, format_spec):\n        return format_spec\nprint(f'{CustomFormat():abc}')\nprint(format(CustomFormat(), 'xyz'))",
        &["abc", "xyz"],
    );
    assert_output(
        "class X:\n    def __init__(self):\n        self.i = 0\n    def __format__(self, spec):\n        self.i += 1\n        return str(self.i) + spec\nx = X()\nprint(f'{x} {x:!}')",
        &["1 2!"],
    );
    assert_output(
        "class Y:\n    def __format__(self, spec):\n        return 'class:' + spec\ny = Y()\ny.__format__ = lambda spec: 'instance:' + spec\nprint(y.__format__('direct'))\nprint(format(y, 'real'))\nprint(f'{y:field}')",
        &["instance:direct", "class:real", "class:field"],
    );
    assert_error(
        "class BadFormatResult:\n    def __format__(self, spec):\n        return 1.0\nprint(format(BadFormatResult(), ''))",
        "runtime error: TypeError: __format__ must return a string, got float",
    );
    assert_error(
        "print(format(object(), 4))",
        "runtime error: TypeError: format() argument 2 must be str, not int",
    );
    assert_output(
        "class B:\n    pass\nb = B()\nprint(format(b), format(b, ''))\nprint(b.__format__(''))",
        &["<B object> <B object>", "<B object>"],
    );
    assert_output("print(object().__format__('')[:14])", &["<object object"]);
    assert_error(
        "class B:\n    pass\nprint(format(B(), 's'))",
        "runtime error: TypeError: unsupported format string passed to B.__format__",
    );
    assert_error(
        "print(object().__format__(3))",
        "runtime error: TypeError: object.__format__() argument 2 must be str, not int",
    );
}

// Adapted from CPython Lib/test/test_builtin.py::test_chr and ::test_ord.
