// Adapted from CPython Lib/test/test_builtin.py::test_round and
// ::test_bug_27936. This covers the core int/float and `__round__` protocol
// behavior without pulling in Decimal/Fraction runtime dependencies.
#[test]
fn cpython_round_builtin_subset() {
    assert_output(
        "print(round(0.0), round(1.0), round(10.0), round(1000000000.0), round(1e20))\nprint(round(-1.0), round(-10.0), round(-1000000000.0), round(-1e20))",
        &[
            "0 1 10 1000000000 100000000000000000000",
            "-1 -10 -1000000000 -100000000000000000000",
        ],
    );
    assert_output(
        "print(round(0.1), round(1.1), round(10.1), round(1000000000.1))\nprint(round(-1.1), round(-10.1), round(-1000000000.1))\nprint(round(0.9), round(9.9), round(999999999.9))\nprint(round(-0.9), round(-9.9), round(-999999999.9))",
        &[
            "0 1 10 1000000000",
            "-1 -10 -1000000000",
            "1 10 1000000000",
            "-1 -10 -1000000000",
        ],
    );
    assert_output(
        "print(round(5.5), round(6.5), round(-5.5), round(-6.5))\nprint(round(-8.0, -1), type(round(-8.0, -1)).__name__)\nprint(type(round(-8.0, 0)).__name__, type(round(-8.0, 1)).__name__)\nprint(round(15.0, -1), round(25.0, -1), round(35.0, -1))",
        &["6 6 -6 -6", "-10.0 float", "float float", "20.0 20.0 40.0"],
    );
    assert_output(
        "print(round(0), round(8), round(-8), type(round(0)).__name__)\nprint(round(-8, -1), type(round(-8, -1)).__name__)\nprint(round(-8, 0), type(round(-8, 0)).__name__)\nprint(round(-8, 1), type(round(-8, 1)).__name__)\nprint(round(1234, None), round(1234.56, None), type(round(1234.56, None)).__name__)",
        &["0 8 -8 int", "-10 int", "-8 int", "-8 int", "1234 1235 int"],
    );
    assert_output(
        "print(round(1234.56, 1), round(1234.56, -1))\nprint(round(number=-8.0, ndigits=-1))",
        &["1234.6 1230.0", "-10.0"],
    );
    assert_output(
        "class TestRound:\n    def __round__(self):\n        return 23\nclass TestRoundWithDigits:\n    def __round__(self, ndigits):\n        return ndigits\nprint(round(TestRound()))\nprint(round(TestRoundWithDigits(), 4))",
        &["23", "4"],
    );
    assert_output(
        "class TestNoRound:\n    pass\nt = TestNoRound()\nt.__round__ = lambda *args: args\nfor expr in [lambda: round(), lambda: round(1, 2, 3), lambda: round(TestNoRound()), lambda: round(t), lambda: round(t, 0), lambda: round(1.2, 'x')]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_type,
// TestType::test_bad_args, and Lib/test/test_descr.py coverage that verifies
// `type(instance)` returns the class object without calling metaclass hooks.
#[test]
fn cpython_type_builtin_subset() {
    assert_output(
        "print(type('').__name__, type('123').__name__, type(()).__name__)\nprint(type('') == type('123'), type('') != type(()))",
        &["str str tuple", "True True"],
    );
    assert_output(
        "print(type(None).__name__, type(True).__name__, type(1).__name__, type(1.5).__name__)\nprint(type([]).__name__, type({}).__name__, type(set()).__name__)",
        &["NoneType bool int float", "list dict set"],
    );
    assert_output(
        "print(type(type('')).__name__, type(len).__name__, type(type(len)).__name__)",
        &["type builtin_function_or_method type"],
    );
    assert_output(
        "class A:\n    pass\na = A()\nprint(type(a) is A, a.__class__ is A, type(A).__name__)",
        &["True True type"],
    );
    assert_output(
        "for name in ['A', 'Ä', '🐍', 'B.A', '42', '']:\n    A = type(name, (), {})\n    print(A.__name__, A.__qualname__, A.__module__)\nclass Base:\n    label = 'base'\ndef dyn_method(self):\n    return self.value + 1\nDynamic = type('Dynamic', (Base,), {'value': 7, 'plus': dyn_method})\ninst = Dynamic()\nprint(Dynamic.__name__, Dynamic.__qualname__, Dynamic.__module__)\nprint(Dynamic.__bases__[0] is Base, Dynamic.label, inst.value, inst.plus())",
        &[
            "A A __main__",
            "Ä Ä __main__",
            "🐍 🐍 __main__",
            "B.A B.A __main__",
            "42 42 __main__",
            "  __main__",
            "Dynamic Dynamic __main__",
            "True base 7 8",
        ],
    );
    assert_output(
        "for expr in [lambda: type(), lambda: type('A', ()), lambda: type('A', (), {}, extra=1), lambda: type(obj=1), lambda: type(b'A', (), {}), lambda: type('A\\0B', (), {}), lambda: type('A', [], {}), lambda: type('A', (), [])]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ValueError",
            "TypeError",
            "TypeError",
        ],
    );
}

