// Adapted from CPython Lib/test/test_int.py::IntStrDigitLimitsTests.
#[test]
fn cpython_int_max_str_digits_runtime_subset() {
    assert_output(
        "import sys\nold_limit = sys.get_int_max_str_digits()\nsys.set_int_max_str_digits(640)\ntry:\n    maxdigits = sys.get_int_max_str_digits()\n    int('1' * maxdigits)\n    int(' ' + '1' * maxdigits)\n    int('1' * maxdigits + ' ')\n    int('+' + '1' * maxdigits)\n    int('-' + '1' * maxdigits)\n    print(len(str(10 ** (maxdigits - 1))))\n    for text in ['1' * (maxdigits + 1), ' ' + '1' * (maxdigits + 1), '1' * (maxdigits + 1) + ' ', '+' + '1' * (maxdigits + 1), '-' + '1' * (maxdigits + 1)]:\n        try:\n            int(text)\n        except ValueError as error:\n            message = str(error)\n            print('int', 'Exceeds the limit' in message, 'conversion' in message)\n    too_big = 10 ** maxdigits\n    for expr in [lambda: str(too_big), lambda: repr(too_big), lambda: repr([too_big])]:\n        try:\n            expr()\n        except ValueError as error:\n            message = str(error)\n            print('render', 'Exceeds the limit' in message, 'conversion' in message)\n    for base in [2, 4, 8, 16, 32]:\n        int('1' * (maxdigits + 1), base)\n    print('power-bases')\n    int('1_1' * (maxdigits // 2))\n    try:\n        int('1_1' * (maxdigits // 2) + '_1')\n    except ValueError as error:\n        message = str(error)\n        print('underscore', 'Exceeds the limit' in message, 'conversion' in message)\nfinally:\n    sys.set_int_max_str_digits(old_limit)",
        &[
            "640",
            "int True True",
            "int True True",
            "int True True",
            "int True True",
            "int True True",
            "render True True",
            "render True True",
            "render True True",
            "power-bases",
            "underscore True True",
        ],
    );
}

// Adapted from CPython Lib/test/test_int.py::PyLongModuleTests and
// `IntStrDigitLimitsTests`: decimal integer formatting is an integer string
// conversion and must honor `sys.set_int_max_str_digits()`, while non-decimal
// power-of-two bases remain unlimited.
#[test]
fn cpython_int_max_str_digits_formatting_subset() {
    assert_output(
        "import sys\nold_limit = sys.get_int_max_str_digits()\nsys.set_int_max_str_digits(640)\ntry:\n    maxdigits = sys.get_int_max_str_digits()\n    ok = 10 ** (maxdigits - 1)\n    too_big = 10 ** maxdigits\n    base_value = 16 ** maxdigits\n    print(len(format(ok, 'd')), len(f'{ok:d}'), len('{}'.format(ok)), len('%d' % ok))\n    for expr in [lambda: format(too_big, ''), lambda: format(too_big, 'd'), lambda: format(too_big, ',d'), lambda: '{}'.format(too_big), lambda: '{:d}'.format(too_big), lambda: '{:,d}'.format(too_big), lambda: f'{too_big}', lambda: f'{too_big:d}', lambda: f'{too_big:,d}', lambda: f'{too_big!s}', lambda: f'{too_big!r}', lambda: f'{too_big!a}', lambda: '%s' % too_big, lambda: '%r' % too_big, lambda: '%a' % too_big, lambda: '%d' % too_big, lambda: '%i' % too_big, lambda: '%u' % too_big]:\n        try:\n            expr()\n        except ValueError as error:\n            message = str(error)\n            print('format', 'Exceeds the limit' in message, 'conversion' in message)\n    print(len(format(base_value, 'x')) == maxdigits + 1)\n    print(len(f'{base_value:x}') == maxdigits + 1)\n    print(len('%x' % base_value) == maxdigits + 1)\nfinally:\n    sys.set_int_max_str_digits(old_limit)",
        &[
            "640 640 640 640",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "format True True",
            "True",
            "True",
            "True",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_iter /
// ::test_next and selected Lib/test/test_iter.py iterator exhaustion cases.
#[test]
fn cpython_iter_next_builtin_subset() {
    assert_output(
        "for value in [('1', '2'), ['1', '2'], '12']:\n    iterator = iter(value)\n    print(next(iterator), next(iterator))\n    try:\n        next(iterator)\n    except StopIteration:\n        print('stopped')\nfor expr in [lambda: iter(), lambda: iter(42, 42)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "1 2",
            "stopped",
            "1 2",
            "stopped",
            "1 2",
            "stopped",
            "TypeError",
            "TypeError",
        ],
    );
    assert_output(
        "iterator = iter(range(2))\nprint(next(iterator))\nprint(next(iterator))\nfor _ in [0, 1]:\n    try:\n        next(iterator)\n    except StopIteration:\n        print('stopped')\nprint(next(iterator, 42))\nclass Iter:\n    def __iter__(self):\n        return self\n    def __next__(self):\n        raise StopIteration\niterator = iter(Iter())\nprint(next(iterator, 42))\ntry:\n    next(iterator)\nexcept StopIteration:\n    print('stopped')\ndef gen():\n    yield 1\n    return\niterator = gen()\nprint(next(iterator))\ntry:\n    next(iterator)\nexcept StopIteration:\n    print('stopped')\nprint(next(iterator, 42))",
        &[
            "0", "1", "stopped", "stopped", "42", "42", "stopped", "1", "stopped", "42",
        ],
    );
    assert_output(
        concat!(
            "HAS_MORE = 1\n",
            "NO_MORE = 2\n",
            "def exhaust(iterator):\n",
            "    list(iterator)\n",
            "state = [False, None]\n",
            "def spam():\n",
            "    if state[0]:\n",
            "        return NO_MORE\n",
            "    state[0] = True\n",
            "    exhaust(state[1])\n",
            "    return HAS_MORE\n",
            "state[1] = iter(spam, NO_MORE)\n",
            "try:\n",
            "    next(state[1])\n",
            "except StopIteration:\n",
            "    print('stopped')\n",
            "print(next(state[1], 'done'))\n",
            "counter = [0]\n",
            "def stop_by_exception():\n",
            "    counter[0] += 1\n",
            "    if counter[0] == 3:\n",
            "        raise StopIteration\n",
            "    return counter[0]\n",
            "print(list(iter(stop_by_exception, 99)))",
        ),
        &["stopped", "done", "[1, 2]"],
    );
    assert_output(
        concat!(
            "def show(label, iterator, mutate=None):\n",
            "    print(label, list(iterator))\n",
            "    if mutate is not None:\n",
            "        mutate()\n",
            "    print(label, list(iterator))\n",
            "items = list(range(5))\n",
            "show('list', iter(items), lambda: items.extend(range(5, 10)))\n",
            "show('tuple', iter((0, 1, 2, 3, 4)))\n",
            "show('string', iter('abcde'))\n",
            "class Sequence:\n",
            "    def __init__(self, n):\n",
            "        self.n = n\n",
            "    def __getitem__(self, index):\n",
            "        if index < self.n:\n",
            "            return index\n",
            "        raise IndexError\n",
            "sequence = Sequence(5)\n",
            "show('sequence', iter(sequence), lambda: setattr(sequence, 'n', 10))\n",
            "state = [0]\n",
            "def spam():\n",
            "    value = state[0]\n",
            "    state[0] = value + 1\n",
            "    if value == 10:\n",
            "        raise AssertionError(\"should not be called after exhaustion\")\n",
            "    return value\n",
            "show('callable', iter(spam, 5))\n",
            "show('range', iter(range(5)))\n",
            "def gen():\n",
            "    for value in range(5):\n",
            "        yield value\n",
            "show('yield', gen())\n",
            "show('enumerate', enumerate(range(5)))",
        ),
        &[
            "list [0, 1, 2, 3, 4]",
            "list []",
            "tuple [0, 1, 2, 3, 4]",
            "tuple []",
            "string ['a', 'b', 'c', 'd', 'e']",
            "string []",
            "sequence [0, 1, 2, 3, 4]",
            "sequence []",
            "callable [0, 1, 2, 3, 4]",
            "callable []",
            "range [0, 1, 2, 3, 4]",
            "range []",
            "yield [0, 1, 2, 3, 4]",
            "yield []",
            "enumerate [(0, 0), (1, 1), (2, 2), (3, 3), (4, 4)]",
            "enumerate []",
        ],
    );
}

// Adapted from CPython Lib/test/test_enumerate.py::EnumerateTestCase and
// Lib/test/test_builtin.py::BuiltinTest::test_zip / ::test_sorted.
#[test]
fn cpython_enumerate_zip_sorted_builtin_subset() {
    assert_output(
        "class G:\n    def __init__(self, seqn):\n        self.seqn = seqn\n    def __getitem__(self, index):\n        return self.seqn[index]\nclass I:\n    def __init__(self, seqn):\n        self.seqn = seqn\n        self.index = 0\n    def __iter__(self):\n        return self\n    def __next__(self):\n        if self.index >= len(self.seqn):\n            raise StopIteration\n        value = self.seqn[self.index]\n        self.index += 1\n        return value\nclass Ig:\n    def __init__(self, seqn):\n        self.seqn = seqn\n    def __iter__(self):\n        for value in self.seqn:\n            yield value\nseq = 'abc'\ne = enumerate(seq)\nprint(iter(e) is e)\nprint(list(enumerate(seq)))\nprint(list(enumerate(G(seq))))\nprint(list(enumerate(I(seq))))\nprint(list(enumerate(Ig(seq))))\nfor empty in [G(''), I(''), Ig('')]:\n    try:\n        next(enumerate(empty))\n    except StopIteration:\n        print('stopped')\nprint(list(enumerate(iterable=Ig(seq))))\nprint(list(enumerate(iterable=Ig(seq), start=0)))\nprint(list(enumerate(start=0, iterable=Ig(seq))))",
        &[
            "True",
            "[(0, 'a'), (1, 'b'), (2, 'c')]",
            "[(0, 'a'), (1, 'b'), (2, 'c')]",
            "[(0, 'a'), (1, 'b'), (2, 'c')]",
            "[(0, 'a'), (1, 'b'), (2, 'c')]",
            "stopped",
            "stopped",
            "stopped",
            "[(0, 'a'), (1, 'b'), (2, 'c')]",
            "[(0, 'a'), (1, 'b'), (2, 'c')]",
            "[(0, 'a'), (1, 'b'), (2, 'c')]",
        ],
    );
    assert_output(
        "class X:\n    def __init__(self, seqn):\n        self.seqn = seqn\n        self.index = 0\n    def __next__(self):\n        if self.index >= len(self.seqn):\n            raise StopIteration\n        value = self.seqn[self.index]\n        self.index += 1\n        return value\nclass N:\n    def __init__(self, seqn):\n        self.seqn = seqn\n    def __iter__(self):\n        return self\nclass E:\n    def __init__(self, seqn):\n        self.seqn = seqn\n    def __iter__(self):\n        return self\n    def __next__(self):\n        3 // 0\nfor expr in [lambda: enumerate(), lambda: enumerate(1), lambda: enumerate('abc', 'a'), lambda: enumerate('abc', 2, 3), lambda: enumerate(iterable=[], x=3), lambda: enumerate(start=0, x=3), lambda: enumerate(x=0, y=3), lambda: enumerate(x=0), lambda: enumerate(X('abc')), lambda: enumerate(N('abc'))]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)\ntry:\n    list(enumerate(E('abc')))\nexcept ZeroDivisionError as error:\n    print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ZeroDivisionError",
        ],
    );
    assert_output(
        "a = (1, 2, 3)\nb = (4, 5, 6)\nprint(list(zip(a, b)))\nprint(list(zip(a, [4, 5, 6])))\nprint(list(zip(a, (4, 5, 6, 7))))\nclass I:\n    def __getitem__(self, index):\n        if index < 0 or index > 2:\n            raise IndexError\n        return index + 4\nprint(list(zip(a, I())))\nprint(list(zip()), list(zip(*[])))\nprint(list(zip(range(5), range(10))))\nprint(sorted([3, 1, 2]))\nprint(sorted([1, 2, 3], key=lambda x: -x))\nprint(sorted([3, 1, 2], reverse=True))\nclass G:\n    pass\nfor expr in [lambda: zip(None), lambda: zip(a, G()), lambda: sorted(), lambda: sorted([], bad=True)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "[(1, 4), (2, 5), (3, 6)]",
            "[(1, 4), (2, 5), (3, 6)]",
            "[(1, 4), (2, 5), (3, 6)]",
            "[(1, 4), (2, 5), (3, 6)]",
            "[] []",
            "[(0, 0), (1, 1), (2, 2), (3, 3), (4, 4)]",
            "[1, 2, 3]",
            "[3, 2, 1]",
            "[3, 2, 1]",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_zip_strict
// and ::test_zip_strict_iterators. MiniPython covers the executable
// strict-length semantics and iterator consumption side effects for the
// supported iterator subset.
#[test]
fn cpython_zip_strict_builtin_subset() {
    assert_output(
        "print(list(zip((1, 2, 3), 'abc', strict=True)))\nprint(list(zip((1, 2), 'abc', strict=False)))\nprint(list(zip(strict=True)))",
        &[
            "[(1, 'a'), (2, 'b'), (3, 'c')]",
            "[(1, 'a'), (2, 'b')]",
            "[]",
        ],
    );
    assert_output(
        "for expr in [lambda: list(zip((1, 2, 3, 4), 'abc', strict=True)), lambda: list(zip((1, 2), 'abc', strict=True)), lambda: list(zip((1, 2), (1, 2), 'abc', strict=True)), lambda: zip([1], bad=True)]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__, error)",
        &[
            "ValueError zip() argument 2 is shorter than argument 1",
            "ValueError zip() argument 2 is longer than argument 1",
            "ValueError zip() argument 3 is longer than arguments 1-2",
            "TypeError 'bad' is an invalid keyword argument for zip()",
        ],
    );
    assert_output(
        "x = iter(range(5))\ny = [0]\nz = iter(range(5))\ntry:\n    list(zip(x, y, z, strict=True))\nexcept ValueError as error:\n    print(error.__class__.__name__)\nprint(next(x), next(z))",
        &["ValueError", "2 1"],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_map and
// ::test_filter.
#[test]
fn cpython_map_filter_builtin_subset() {
    assert_output(
        "class Squares:\n    def __init__(self, stop):\n        self.stop = stop\n    def __getitem__(self, index):\n        if index < 0 or index >= self.stop:\n            raise IndexError\n        return index * index\nprint(list(map(lambda x: x * x, range(1, 4))))\nprint(list(map(lambda x, y: x + y, [1, 3, 2], [9, 1, 4])))\ndef plus(*values):\n    total = 0\n    for value in values:\n        total += value\n    return total\nprint(list(map(plus, [1, 3, 7])))\nprint(list(map(plus, [1, 3, 7], [4, 9, 2])))\nprint(list(map(plus, [1, 3, 7], [4, 9, 2], [1, 1, 0])))\nprint(list(map(int, Squares(10))))\ndef Max(a, b):\n    if a is None:\n        return b\n    if b is None:\n        return a\n    return max(a, b)\nprint(list(map(Max, Squares(3), Squares(2))))",
        &[
            "[1, 4, 9]",
            "[10, 4, 6]",
            "[1, 3, 7]",
            "[5, 12, 9]",
            "[6, 13, 9]",
            "[0, 1, 4, 9, 16, 25, 36, 49, 64, 81]",
            "[0, 1]",
        ],
    );
    assert_output(
        "class Squares:\n    def __init__(self, stop):\n        self.stop = stop\n    def __getitem__(self, index):\n        if index < 0 or index >= self.stop:\n            raise IndexError\n        return index * index\nprint(list(filter(lambda c: 'a' <= c <= 'z', 'Hello World')))\nprint(list(filter(None, [1, 'hello', [], [3], '', None, 9, 0])))\nprint(list(filter(lambda x: x > 0, [1, -3, 9, 0, 2])))\nprint(list(filter(None, Squares(10))))\nprint(list(filter(lambda x: x % 2, Squares(10))))\nprint(list(filter(None, (1, 2))))\nprint(list(filter(lambda x: x >= 3, (1, 2, 3, 4))))\nclass BadSeq:\n    def __getitem__(self, index):\n        if index < 4:\n            return 42\n        raise ValueError\ndef badfunc():\n    pass\nfor expr in [lambda: filter(), lambda: filter(None), lambda: filter(None, 42), lambda: list(filter(42, (1, 2))), lambda: list(filter(badfunc, range(5))), lambda: map(), lambda: map(lambda x: x), lambda: map(lambda x: x, 42), lambda: list(map(None, [1]))]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)\ntry:\n    list(filter(lambda x: x, BadSeq()))\nexcept ValueError as error:\n    print(error.__class__.__name__)",
        &[
            "['e', 'l', 'l', 'o', 'o', 'r', 'l', 'd']",
            "[1, 'hello', [3], 9]",
            "[1, 9, 2]",
            "[1, 4, 9, 16, 25, 36, 49, 64, 81]",
            "[1, 9, 25, 49, 81]",
            "[1, 2]",
            "[3, 4]",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ValueError",
        ],
    );
}

// Adapted from CPython Lib/test/test_list.py::ListTest::test_basic,
// Lib/test/test_tuple.py::TupleTest::test_constructors, and
// Lib/test/test_set.py::TestSet constructor/literal coverage.
#[test]
fn cpython_sequence_constructor_builtins_subset() {
    assert_output(
        "print(list([]))\nitems = [0, 1, 2, 3]\ncopy = list(items)\nprint(items == copy, items is copy)\nprint(list(()))\nprint(list((0, 1, 2, 3)))\nprint(list(''))\nprint(list('spam'))\nprint(list(x for x in range(10) if x % 2))\nprint(tuple())\nvalues = (0, 1, 2, 3)\ncopy = tuple(values)\nprint(values == copy, values is copy)\nprint(tuple([]))\nprint(tuple([0, 1, 2, 3]))\nprint(tuple(''))\nprint(tuple('spam'))\nprint(tuple(x for x in range(10) if x % 2))\nprint(sorted(set()))\nprint(sorted(set([1, 2, 1])))\nprint(sorted(set('aba')))",
        &[
            "[]",
            "True False",
            "[]",
            "[0, 1, 2, 3]",
            "[]",
            "['s', 'p', 'a', 'm']",
            "[1, 3, 5, 7, 9]",
            "()",
            "True True",
            "()",
            "(0, 1, 2, 3)",
            "()",
            "('s', 'p', 'a', 'm')",
            "(1, 3, 5, 7, 9)",
            "[]",
            "[1, 2]",
            "['a', 'b']",
        ],
    );
    assert_output(
        concat!(
            "s = set()\n",
            "alias = s\n",
            "print(s.__init__('simsalabim'), sorted(s), s is alias)\n",
            "print(s.__init__('madagascar'), sorted(s), s is alias)\n",
            "print(s.__init__(), sorted(s), s is alias)\n",
            "s = set([1, 2])\n",
            "print(s.__init__(s), sorted(s))\n",
            "for expr in [lambda: s.__init__(s, 2), lambda: s.__init__(1), lambda: s.__init__([3, []])]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__, sorted(s))",
        ),
        &[
            "None ['a', 'b', 'i', 'l', 'm', 's'] True",
            "None ['a', 'c', 'd', 'g', 'm', 'r', 's'] True",
            "None [] True",
            "None []",
            "TypeError []",
            "TypeError []",
            "TypeError [3]",
        ],
    );
    assert_output(
        concat!(
            "s = set(range(3))\n",
            "t = set(s)\n",
            "print(s == t, s is t)\n",
            "print(set([1, 2, 3]) == {1, 2, 3})\n",
            "dedup = {1, 1.0, True}\n",
            "stored = dedup.pop()\n",
            "print(len(dedup) + 1, type(stored).__name__)\n",
            "events = []\n",
            "def record(obj):\n",
            "    events.append(obj)\n",
            "{record(1), record(2), record(3)}\n",
            "print(events)\n",
            "try:\n",
            "    hash(set('abc'))\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)\n",
            "source = set('abc')\n",
            "dup = source.copy()\n",
            "print(source == dup, source is dup, type(dup).__name__)",
        ),
        &[
            "True False",
            "True",
            "1 int",
            "[1, 2, 3]",
            "TypeError",
            "True False set",
        ],
    );
    assert_output(
        "for expr in [lambda: list(1, 2), lambda: tuple(1, 2), lambda: set(1, 2), lambda: list(sequence=[]), lambda: tuple(sequence=()), lambda: set(sequence=[]), lambda: list(42), lambda: tuple(42), lambda: set(42), lambda: set([[]])]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestFrozenSet and the common
// TestJointOps cases, plus Lib/test/test_collections.py Set/MutableSet ABC
// registration checks. This is a first-pass exact `frozenset` surface, not
// frozenset subclassing.
#[test]
fn cpython_frozenset_basic_subset() {
    assert_output(
        concat!(
            "from collections.abc import Set, MutableSet, Hashable\n",
            "fs = frozenset('abca')\n",
            "print(sorted(list(fs)), len(fs), 'a' in fs, 'z' in fs)\n",
            "empty_a = frozenset()\n",
            "empty_b = frozenset([])\n",
            "empty_c = frozenset(())\n",
            "print(empty_a is empty_b, empty_b is empty_c, frozenset('') is empty_a)\n",
            "before = sorted(list(fs))\n",
            "print(fs.__init__('zz'), sorted(list(fs)) == before)\n",
            "copy = frozenset(fs)\n",
            "print(copy is fs, copy == set('abc'), type(copy).__name__)\n",
            "print(isinstance(fs, Set), issubclass(frozenset, Set), isinstance(fs, MutableSet), issubclass(frozenset, MutableSet), isinstance(fs, Hashable))\n",
            "print(repr(frozenset()))\n",
            "print(type(fs.union('cd')).__name__, sorted(list(fs.union('cd'))))\n",
            "print(type(fs.intersection('bc')).__name__, sorted(list(fs.intersection('bc'))))\n",
            "print(type(fs.difference('bc')).__name__, sorted(list(fs.difference('bc'))))\n",
            "print(type(fs.symmetric_difference('bcd')).__name__, sorted(list(fs.symmetric_difference('bcd'))))\n",
            "print(type(fs | set('cd')).__name__, sorted(list(fs | set('cd'))))\n",
            "print(type(set('ab') | fs).__name__, sorted(list(set('ab') | fs)))\n",
            "print(fs.isdisjoint('xyz'), fs.isdisjoint('za'))\n",
            "print(frozenset('ab') < frozenset('abc'), frozenset('abc') >= set('ab'))\n",
            "print(hash(frozenset('abc')) == hash(frozenset('cba')))\n",
            "d = {frozenset('ab'): 42}\n",
            "print(d[frozenset('ba')])\n",
            "print(len(set([frozenset('ab'), frozenset('ba')])))\n",
            "print(hasattr(fs, 'add'), hasattr(fs, 'remove'), fs.copy() is fs)\n",
            "try:\n",
            "    frozenset([[]])\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)",
        ),
        &[
            "['a', 'b', 'c'] 3 True False",
            "True True True",
            "None True",
            "True True frozenset",
            "True True False False True",
            "frozenset()",
            "frozenset ['a', 'b', 'c', 'd']",
            "frozenset ['b', 'c']",
            "frozenset ['a']",
            "frozenset ['a', 'd']",
            "frozenset ['a', 'b', 'c', 'd']",
            "set ['a', 'b', 'c']",
            "True False",
            "True True",
            "True",
            "42",
            "1",
            "False False True",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestSetSubclass and
// TestFrozenSetSubclass. MiniPython keeps the constructor, iteration,
// membership, hashing, ABC registration, custom __new__, and method result
// semantics covered here.
#[test]
fn cpython_set_and_frozenset_subclass_subset() {
    assert_output(
        concat!(
            "from collections.abc import Set, MutableSet, Hashable\n",
            "class SetSubclass(set):\n",
            "    pass\n",
            "u = SetSubclass([1, 2, 2])\n",
            "print(type(u) is SetSubclass, isinstance(u, set), issubclass(SetSubclass, set))\n",
            "print(sorted(list(u)), set(u) == {1, 2}, len(u), 1 in u, 3 in u)\n",
            "print(isinstance(u, Set), isinstance(u, MutableSet), isinstance(u, Hashable))\n",
            "try:\n",
            "    hash(u)\n",
            "except TypeError:\n",
            "    print('set subclass hash TypeError')\n",
            "u.add(3)\n",
            "u.discard(2)\n",
            "print(sorted(list(u)), type(u.copy()).__name__)\n",
            "print(u == {1, 3}, {1, 3} == u, u < {1, 3, 4})\n",
            "print(type(u.union([4])).__name__, sorted(u.union([4])))\n",
            "u |= {5}\n",
            "print(type(u).__name__, sorted(list(u)))\n",
            "try:\n",
            "    SetSubclass(sequence=())\n",
            "except TypeError:\n",
            "    print('set kwargs TypeError')\n",
            "class SetSubclassWithInit(set):\n",
            "    def __init__(self, arg, newarg=None):\n",
            "        super().__init__(arg)\n",
            "        self.newarg = newarg\n",
            "v = SetSubclassWithInit([1, 2], newarg=3)\n",
            "print(type(v) is SetSubclassWithInit, set(v) == {1, 2}, v.newarg)\n",
            "class SetSubclassWithNew(set):\n",
            "    def __new__(cls, arg, newarg=None):\n",
            "        self = super().__new__(cls, arg)\n",
            "        self.newarg = newarg\n",
            "        return self\n",
            "w = SetSubclassWithNew([1, 2])\n",
            "print(type(w) is SetSubclassWithNew, set(w) == {1, 2}, w.newarg is None)\n",
            "try:\n",
            "    SetSubclassWithNew([1, 2], newarg=3)\n",
            "except TypeError:\n",
            "    print('set new kwargs TypeError')\n",
            "class FrozenSetSubclass(frozenset):\n",
            "    pass\n",
            "f = FrozenSetSubclass([1, 2, 2])\n",
            "print(type(f) is FrozenSetSubclass, isinstance(f, frozenset), issubclass(FrozenSetSubclass, frozenset))\n",
            "print(sorted(list(f)), set(f) == {1, 2}, len(f), 2 in f, 3 in f)\n",
            "print(isinstance(f, Set), isinstance(f, MutableSet), isinstance(f, Hashable))\n",
            "print(type(f.copy()).__name__, f.copy() is f)\n",
            "print(f == frozenset([1, 2]), frozenset([1, 2]) == f, f < frozenset([1, 2, 3]))\n",
            "print(type(f.union([3])).__name__, sorted(f.union([3])))\n",
            "print(hash(f) == hash(frozenset([1, 2])))\n",
            "try:\n",
            "    FrozenSetSubclass(sequence=())\n",
            "except TypeError:\n",
            "    print('frozenset kwargs TypeError')\n",
            "class FrozenSetSubclassWithInit(frozenset):\n",
            "    def __init__(self, arg, newarg=None):\n",
            "        self.newarg = newarg\n",
            "g = FrozenSetSubclassWithInit([1, 2], newarg=3)\n",
            "print(type(g) is FrozenSetSubclassWithInit, set(g) == {1, 2}, g.newarg)\n",
            "class FrozenSetSubclassWithNew(frozenset):\n",
            "    def __new__(cls, arg, newarg=None):\n",
            "        self = super().__new__(cls, arg)\n",
            "        self.newarg = newarg\n",
            "        return self\n",
            "h = FrozenSetSubclassWithNew([1, 2], newarg=3)\n",
            "print(type(h) is FrozenSetSubclassWithNew, set(h) == {1, 2}, h.newarg)\n",
            "base = FrozenSetSubclass(range(3))\n",
            "constructed = FrozenSetSubclass(base)\n",
            "print(base is constructed, base == constructed, sorted(list(constructed)))\n",
            "empty = FrozenSetSubclass()\n",
            "nested_empty = FrozenSetSubclass(empty)\n",
            "print(empty is nested_empty, empty == nested_empty)\n",
            "empty_ids = [\n",
            "    id(FrozenSetSubclass()), id(FrozenSetSubclass([])), id(FrozenSetSubclass(())), id(FrozenSetSubclass('')),\n",
            "    id(FrozenSetSubclass(range(0))), id(FrozenSetSubclass(frozenset())), id(frozenset()), id(empty), id(FrozenSetSubclass(empty)),\n",
            "]\n",
            "print(len(set(empty_ids)) == len(empty_ids))\n",
            "base_copy = base.copy()\n",
            "print(base_copy is base, base_copy == base, type(base_copy).__name__)\n",
            "class SetSubclassWithSlots(set):\n",
            "    __slots__ = ('x', 'y', '__dict__')\n",
            "slot_set = SetSubclassWithSlots([2, 1])\n",
            "slot_set.x = 10\n",
            "slot_set.y = 20\n",
            "slot_set.extra = 30\n",
            "print(type(slot_set).__name__, sorted(list(slot_set)), slot_set.x, slot_set.y, slot_set.extra)\n",
            "class FrozenSetSubclassWithSlots(frozenset):\n",
            "    __slots__ = ('x', 'y', '__dict__')\n",
            "slot_frozen = FrozenSetSubclassWithSlots([2, 1])\n",
            "slot_frozen.x = 11\n",
            "slot_frozen.y = 22\n",
            "slot_frozen.extra = 33\n",
            "print(type(slot_frozen).__name__, sorted(list(slot_frozen)), slot_frozen.x, slot_frozen.y, slot_frozen.extra)",
        ),
        &[
            "True True True",
            "[1, 2] True 2 True False",
            "True True False",
            "set subclass hash TypeError",
            "[1, 3] set",
            "True True True",
            "set [1, 3, 4]",
            "SetSubclass [1, 3, 5]",
            "set kwargs TypeError",
            "True True 3",
            "True True True",
            "set new kwargs TypeError",
            "True True True",
            "[1, 2] True 2 True False",
            "True False True",
            "frozenset False",
            "True True True",
            "frozenset [1, 2, 3]",
            "True",
            "frozenset kwargs TypeError",
            "True True 3",
            "True True 3",
            "False True [0, 1, 2]",
            "False True",
            "True",
            "False True frozenset",
            "SetSubclassWithSlots [1, 2] 10 20 30",
            "FrozenSetSubclassWithSlots [1, 2] 11 22 33",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestJointOps. This keeps the
// common set/frozenset behavioral contract separate from mutation-only set
// methods and subclass/pickle/GC coverage.
#[test]
fn cpython_set_frozenset_joint_ops_subset() {
    assert_output(
        concat!(
            "for typ in (set, frozenset):\n",
            "    s = typ('simsalabim')\n",
            "    d = dict.fromkeys('simsalabim')\n",
            "    print(typ.__name__, sorted(s), len(s) == len(d))\n",
            "    print([c in s for c in 'abcxyz'])\n",
            "    nested = typ([frozenset('abc')])\n",
            "    print(typ('abc') in nested)\n",
            "    rejected = 0\n",
            "    for op in (lambda: s | 'madagascar', lambda: s & 'madagascar', lambda: s - 'madagascar', lambda: s ^ 'madagascar'):\n",
            "        try:\n",
            "            op()\n",
            "        except TypeError:\n",
            "            rejected += 1\n",
            "    print(rejected)\n",
            "    print(type(s.union('madagascar')).__name__, sorted(s.union('madagascar')))\n",
            "    print(type(s.intersection('madagascar')).__name__, sorted(s.intersection('madagascar')))\n",
            "    print(type(s.difference('madagascar')).__name__, sorted(s.difference('madagascar')))\n",
            "    print(type(s.symmetric_difference('madagascar')).__name__, sorted(s.symmetric_difference('madagascar')))\n",
            "    p, q, r = typ('ab'), typ('abcde'), typ('def')\n",
            "    print(p < q, p <= q, q <= q, q > p, q >= p, q < r, q <= r, q > r, q >= r)\n",
            "    print(typ('a').issubset('abc'), typ('abc').issuperset('a'), typ('a').issubset('cbs'), typ('cbs').issuperset('a'))",
        ),
        &[
            "set ['a', 'b', 'i', 'l', 'm', 's'] True",
            "[True, True, False, False, False, False]",
            "True",
            "4",
            "set ['a', 'b', 'c', 'd', 'g', 'i', 'l', 'm', 'r', 's']",
            "set ['a', 'm', 's']",
            "set ['b', 'i', 'l']",
            "set ['b', 'c', 'd', 'g', 'i', 'l', 'r']",
            "True True True True True False False False False",
            "True True False False",
            "frozenset ['a', 'b', 'i', 'l', 'm', 's'] True",
            "[True, True, False, False, False, False]",
            "True",
            "4",
            "frozenset ['a', 'b', 'c', 'd', 'g', 'i', 'l', 'm', 'r', 's']",
            "frozenset ['a', 'm', 's']",
            "frozenset ['b', 'i', 'l']",
            "frozenset ['b', 'c', 'd', 'g', 'i', 'l', 'r']",
            "True True True True True False False False False",
            "True True False False",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestJointOps equality,
// set-of-frozensets, and isdisjoint matrix cases.
#[test]
fn cpython_set_frozenset_relationship_matrix_subset() {
    assert_output(
        concat!(
            "args = ['', 'a', 'ab', 'abc', 'ababac', 'cdc', 'cc', 'efgfe', 'ccb', 'ef']\n",
            "constructors = (set, frozenset, dict.fromkeys, str, list, tuple)\n",
            "for typ in (set, frozenset):\n",
            "    word = 'simsalabim'\n",
            "    otherword = 'madagascar'\n",
            "    s = typ(word)\n",
            "    print(typ.__name__, s == set(word), s == frozenset(word), s == word, s != otherword)\n",
            "    print(len(typ(map(frozenset, ['abcdef', 'bcd', 'bdcb', 'fed', 'fedccba']))))\n",
            "    failures = 0\n",
            "    true_count = 0\n",
            "    false_count = 0\n",
            "    for larg in args:\n",
            "        s1 = typ(larg)\n",
            "        for rarg in args:\n",
            "            for C in constructors:\n",
            "                s2 = C(rarg)\n",
            "                actual = s1.isdisjoint(s2)\n",
            "                expected = not set(s1).intersection(s2)\n",
            "                if actual:\n",
            "                    true_count += 1\n",
            "                else:\n",
            "                    false_count += 1\n",
            "                if actual != expected or not (actual is True or actual is False):\n",
            "                    failures += 1\n",
            "    print(failures, true_count, false_count)"
        ),
        &[
            "set True True False True",
            "3",
            "0 342 258",
            "frozenset True True False True",
            "3",
            "0 342 258",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestJointOps union,
// intersection, difference, and symmetric_difference constructor matrix cases.
#[test]
fn cpython_set_frozenset_algebra_matrix_subset() {
    assert_output(
        concat!(
            "constructors = (set, frozenset, dict.fromkeys, str, list, tuple)\n",
            "for typ in (set, frozenset):\n",
            "    failures = 0\n",
            "    for C in constructors:\n",
            "        if typ('abcba').union(C('cdc')) != set('abcd'):\n",
            "            failures += 1\n",
            "        if typ('abcba').union(C('efgfe')) != set('abcefg'):\n",
            "            failures += 1\n",
            "        if typ('abcba').union(C('ccb')) != set('abc'):\n",
            "            failures += 1\n",
            "        if typ('abcba').union(C('ef'), C('fg')) != set('abcefg'):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('cdc')) != set('c'):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('efgfe')) != set(''):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('ccb')) != set('bc'):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('cbcf'), C('bag')) != set('b'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('cdc')) != set('ab'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('efgfe')) != set('abc'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('ccb')) != set('a'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('a'), C('b')) != set('c'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('cdc')) != set('abd'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('efgfe')) != set('abcefg'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('ccb')) != set('a'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('ef')) != set('abcef'):\n",
            "            failures += 1\n",
            "    x = typ()\n",
            "    issue_6573 = x.union(set([1]), x, set([2])) == typ([1, 2])\n",
            "    print(typ.__name__, failures, issue_6573)\n",
            "    print(type(typ('abc').union('d')).__name__, type(typ('abc').intersection('bc')).__name__, type(typ('abc').difference('bc')).__name__, type(typ('abc').symmetric_difference('bc')).__name__)"
        ),
        &[
            "set 0 True",
            "set set set set",
            "frozenset 0 True",
            "frozenset frozenset frozenset frozenset",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestSet mutation method cases:
// clear, add, remove, discard, pop, and update. Subclass, pickle, GC, and
// exact KeyError object identity checks are left for later object-model work.
#[test]
fn cpython_set_mutation_methods_subset() {
    assert_output(
        concat!(
            "s = set('simsalabim')\n",
            "s.clear()\n",
            "print(s == set(), len(s))\n",
            "s = set('simsalabim')\n",
            "print(s.add('Q'), 'Q' in s)\n",
            "dup = s.copy()\n",
            "print(s.add('Q'), s == dup)\n",
            "for expr in [lambda: s.add([]), lambda: s.remove([]), lambda: s.discard([])]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__)\n",
            "s.remove('a')\n",
            "print('a' in s)\n",
            "try:\n",
            "    s.remove('not-there')\n",
            "except KeyError as error:\n",
            "    print(error.__class__.__name__)\n",
            "nested = set([frozenset('simsalabim')])\n",
            "print(set('simsalabim') in nested)\n",
            "nested.remove(set('simsalabim'))\n",
            "print(set('simsalabim') in nested)\n",
            "nested.discard(set('simsalabim'))\n",
            "print(len(nested))\n",
            "items = set('abc')\n",
            "seen = []\n",
            "while len(items):\n",
            "    elem = items.pop()\n",
            "    print(elem in items)\n",
            "    seen.append(elem)\n",
            "print(sorted(seen))\n",
            "try:\n",
            "    items.pop()\n",
            "except KeyError as error:\n",
            "    print(error.__class__.__name__)\n",
            "s = set('abcba')\n",
            "print(s.update('cdc'), sorted(s))\n",
            "print(s.update(frozenset('ef')), sorted(s))\n",
            "try:\n",
            "    s.update([[]])\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)",
        ),
        &[
            "True 0",
            "None True",
            "None True",
            "TypeError",
            "TypeError",
            "TypeError",
            "False",
            "KeyError",
            "True",
            "False",
            "0",
            "False",
            "False",
            "False",
            "['a', 'b', 'c']",
            "KeyError",
            "None ['a', 'b', 'c', 'd']",
            "None ['a', 'b', 'c', 'd', 'e', 'f']",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestSet remove KeyError payload
// and direct set-key membership cases.
#[test]
fn cpython_set_direct_lookup_and_keyerror_payload_subset() {
    assert_output(
        concat!(
            "s = set('simsalabim')\n",
            "for value in ['Q', (1,)]:\n",
            "    try:\n",
            "        s.remove(value)\n",
            "    except KeyError as error:\n",
            "        print(error.args[0] == value, type(error.args[0]).__name__)\n",
            "key = set([3, 4])\n",
            "try:\n",
            "    s.remove(key)\n",
            "except KeyError as error:\n",
            "    print(error.args[0] is key)\n",
            "myfrozenset = frozenset(range(3))\n",
            "myset = {myfrozenset, 'abc', 1}\n",
            "print(set(range(3)) in myset)\n",
            "print(set(range(1)) in myset)\n",
            "myset.discard(set(range(3)))\n",
            "print(myset == {'abc', 1})\n",
            "for key in [set(range(1)), set(range(3))]:\n",
            "    try:\n",
            "        myset.remove(key)\n",
            "    except KeyError as error:\n",
            "        print(error.args[0] is key, error.__class__.__name__)\n",
            "myset = {'a'}\n",
            "elem = [1, 2, 3]\n",
            "for op in [lambda: elem in myset, lambda: myset.add(elem), lambda: myset.discard(elem)]:\n",
            "    try:\n",
            "        op()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__)"
        ),
        &[
            "True str",
            "True tuple",
            "True",
            "True",
            "False",
            "True",
            "True KeyError",
            "True KeyError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestSet.test_unhashable_element.
// TypeError is used for genuinely unhashable elements, but exceptions raised by
// a user-defined __hash__ method must propagate unchanged.
#[test]
fn cpython_set_hash_exception_propagation_subset() {
    assert_output(
        concat!(
            "myset = {'a'}\n",
            "class HashError:\n",
            "    def __hash__(self):\n",
            "        raise KeyError('error')\n",
            "elem = HashError()\n",
            "for op in [lambda: elem in myset, lambda: myset.add(elem), lambda: myset.discard(elem)]:\n",
            "    try:\n",
            "        op()\n",
            "    except KeyError as error:\n",
            "        print(error.__class__.__name__, error.args[0])",
        ),
        &["KeyError error", "KeyError error", "KeyError error"],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestJointOps.test_badcmp.
// Set insertion and lookup must call rich equality after a hash collision, and
// comparison exceptions must propagate.
#[test]
fn cpython_set_bad_comparison_errors_subset() {
    assert_output(
        concat!(
            "class BadCmp:\n",
            "    def __hash__(self):\n",
            "        return 1\n",
            "    def __eq__(self, other):\n",
            "        raise RuntimeError\n",
            "def result(fn):\n",
            "    try:\n",
            "        fn()\n",
            "    except RuntimeError as error:\n",
            "        print(error.__class__.__name__)\n",
            "s = set([BadCmp()])\n",
            "result(lambda: set([BadCmp(), BadCmp()]))\n",
            "result(lambda: s.__contains__(BadCmp()))\n",
            "result(lambda: s.add(BadCmp()))\n",
            "result(lambda: s.discard(BadCmp()))\n",
            "result(lambda: s.remove(BadCmp()))",
        ),
        &[
            "RuntimeError",
            "RuntimeError",
            "RuntimeError",
            "RuntimeError",
            "RuntimeError",
        ],
    );
}

