// Adapted from CPython Lib/test/test_types.py::MappingProxyTests::test_customdict.
// MiniPython uses a user-defined mapping object instead of a dict subclass in
// this slice, so the same observable forwarding behavior can be covered before
// the broader built-in-subclass storage model is complete.
#[test]
fn cpython_types_mappingproxy_custom_mapping_subset() {
    assert_output(
        concat!(
            "from types import MappingProxyType\n",
            "class CustomMapping:\n",
            "    def __init__(self):\n",
            "        self.store = {'key': 'value'}\n",
            "    def __contains__(self, key):\n",
            "        if key == 'magic':\n",
            "            return True\n",
            "        return key in self.store\n",
            "    def __iter__(self):\n",
            "        return iter(('iter',))\n",
            "    def __len__(self):\n",
            "        return 500\n",
            "    def copy(self):\n",
            "        return 'copy'\n",
            "    def keys(self):\n",
            "        return 'keys'\n",
            "    def items(self):\n",
            "        return 'items'\n",
            "    def values(self):\n",
            "        return 'values'\n",
            "    def __getitem__(self, key):\n",
            "        if key in self.store:\n",
            "            return 'getitem=' + self.store[key]\n",
            "        raise KeyError(key)\n",
            "    def get(self, key, default=None):\n",
            "        if key in self.store:\n",
            "            return 'get=' + self.store[key]\n",
            "        return 'get=default=' + str(default)\n",
            "view = MappingProxyType(CustomMapping())\n",
            "print('key' in view, 'magic' in view, 'xxx' in view)\n",
            "print(view['key'])\n",
            "try:\n",
            "    view.__getitem__('xxx')\n",
            "except KeyError as error:\n",
            "    print(error.__class__.__name__)\n",
            "print(tuple(view), len(view))\n",
            "print(view.copy())\n",
            "print(view.get('key'), view.get('xxx'))\n",
            "print(view.items(), view.keys(), view.values())"
        ),
        &[
            "True True False",
            "getitem=value",
            "KeyError",
            "('iter',) 500",
            "copy",
            "get=value get=default=None",
            "items keys values",
        ],
    );
}

// Adapted from CPython Lib/test/test_types.py::MappingProxyTests::test_hash.
