// Adapted from CPython Lib/test/test_compile.py::TestSourcePositions::
// test_multiline_assert_rewritten_as_method_call. This covers the public-AST
// compile path used by the source-position suite without claiming MiniPython
// has CPython's full code-object co_positions() model.
#[test]
fn cpython_compile_source_positions_multiline_assert_rewrite_subset() {
    assert_output(
        r#"import ast
tree = ast.parse("assert (\n42\n)")
old_node = tree.body[0]
new_node = ast.Expr(
    ast.Call(
        ast.Attribute(
            ast.Name("spam", ast.Load()),
            "eggs",
            ast.Load(),
        ),
        [],
        [],
    )
)
ast.copy_location(new_node, old_node)
ast.fix_missing_locations(new_node)
tree.body[0] = new_node
compile(tree, "<test>", "exec")
print("ok")"#,
        &["ok"],
    );
}

// Adapted from CPython Lib/test/test_compile.py::TestStaticAttributes.
// CPython collects Store targets named exactly `self.<attr>` into a sorted
// tuple on the nearest class as `__static_attributes__`.
#[test]
fn cpython_compile_static_attributes_exact_subset() {
    assert_output(
        "class C:\n    def f(self):\n        self.a = self.b = 42\n        self.f()\n        self.arr[3]\nprint(isinstance(C.__static_attributes__, tuple), sorted(C.__static_attributes__))",
        &["True ['a', 'b']"],
    );
    assert_output(
        "class C:\n    def f(self):\n        self.x = 1\n        self.y = 2\n        self.x = 3\n    def g(self, obj):\n        self.y = 4\n        self.z = 5\n        def h(self, a):\n            self.u = 6\n            self.v = 7\n        obj.self = 8\nprint(sorted(C.__static_attributes__))",
        &["['u', 'v', 'x', 'y', 'z']"],
    );
    assert_output(
        "class C:\n    def f(self):\n        self.x = 42\n        self.y = 42\n    class D:\n        def g(self):\n            self.y = 42\n            self.z = 42\nprint(sorted(C.__static_attributes__), sorted(C.D.__static_attributes__))",
        &["['x', 'y'] ['y', 'z']"],
    );
    assert_output(
        "class C:\n    def f(self):\n        self.x = 42\n        self.y = 42\nclass D(C):\n    def g(self):\n        self.y = 42\n        self.z = 42\nprint(sorted(C.__static_attributes__), sorted(D.__static_attributes__))",
        &["['x', 'y'] ['y', 'z']"],
    );
}

// Adapted from CPython Lib/test/test_type_params.py examples for function,
// class, and type-alias type parameters. MiniPython keeps the same observable
// metadata surface for the supported subset: __type_params__, __name__,
// __bound__, __default__, and __value__.
#[test]
fn cpython_type_params_metadata_subset() {
    assert_output(
        "def func[T: int = str](x: T) -> T:\n    return x\nprint(func.__type_params__[0].__name__, func.__type_params__[0].__bound__.__name__, func.__type_params__[0].__default__.__name__)\nprint(func.__annotations__[\"x\"].__name__, func.__annotations__[\"return\"].__name__)",
        &["T int str", "T T"],
    );
    assert_output(
        "class ClassA[X: int = str]:\n    pass\nprint(ClassA.__type_params__[0].__name__, ClassA.__type_params__[0].__bound__.__name__, ClassA.__type_params__[0].__default__.__name__)",
        &["X int str"],
    );
    assert_output(
        "class Base:\n    pass\nclass ClassA[X](Base):\n    pass\nprint(ClassA.__type_params__[0].__name__, ClassA.__bases__[0].__name__)",
        &["X Base"],
    );
    assert_output(
        "type Alias[T: int = str] = int\nprint(Alias.__name__, Alias.__value__.__name__, Alias.__type_params__[0].__name__)",
        &["Alias int T"],
    );
    assert_output(
        "def trailing[T,]():\n    pass\nclass Generic[T, *Ts, **P,]:\n    pass\ntype Alias[T, *Ts, **P,] = int\nprint(trailing.__type_params__[0].__name__)\nprint(Generic.__type_params__[0].__name__, Generic.__type_params__[1].__kind__, Generic.__type_params__[2].__kind__)\nprint(Alias.__type_params__[0].__name__, Alias.__type_params__[1].__kind__, Alias.__type_params__[2].__kind__)",
        &["T", "T TypeVarTuple ParamSpec", "T TypeVarTuple ParamSpec"],
    );
    assert_output(
        "def constrained[T: (int, str) = bool]():\n    pass\nprint(constrained.__type_params__[0].__bound__[0].__name__, constrained.__type_params__[0].__bound__[1].__name__, constrained.__type_params__[0].__default__.__name__)",
        &["int str bool"],
    );
}

// Adapted from CPython Lib/test/test_type_params.py examples that combine
// type parameter scopes with parameterized class bases and annotations.
// MiniPython exposes a compact GenericAlias surface with __origin__ and
// __args__ for the supported subset.
#[test]
fn cpython_type_params_generic_alias_subset() {
    assert_output(
        "class Base[T]:\n    label = \"base\"\nclass ClassA[T](Base[T]):\n    pass\nprint(ClassA.__type_params__[0].__name__, ClassA.__bases__[0].__name__, ClassA.label)",
        &["T Base base"],
    );
    assert_output(
        "def func[T](items: list[T]) -> dict[str, T]:\n    return {}\nprint(func.__annotations__[\"items\"].__origin__.__name__, func.__annotations__[\"items\"].__args__[0].__name__)\nprint(func.__annotations__[\"return\"].__origin__.__name__, func.__annotations__[\"return\"].__args__[0].__name__, func.__annotations__[\"return\"].__args__[1].__name__)",
        &["list T", "dict str T"],
    );
    assert_output(
        "type Alias[T] = dict[str, T]\nprint(Alias.__value__.__origin__.__name__, Alias.__value__.__args__[0].__name__, Alias.__value__.__args__[1].__name__)",
        &["dict str T"],
    );
}

// Adapted from CPython's `type_alias` grammar rule and PEP 695 soft-keyword
// behavior. `type` starts a type alias only in the statement form
// `type NAME [type_params] = expression`; otherwise it remains an ordinary name.
#[test]
fn cpython_type_alias_statement_subset() {
    assert_output(
        "type Alias = int\nprint(Alias.__name__, Alias.__value__.__name__)",
        &["Alias int"],
    );
    assert_output(
        "type Pair = tuple[int, str]\nprint(Pair.__name__, Pair.__value__.__origin__.__name__, Pair.__value__.__args__[0].__name__, Pair.__value__.__args__[1].__name__)",
        &["Pair tuple int str"],
    );
    assert_output(
        "type Alias[T] = list[T]\nprint(Alias.__name__, Alias.__type_params__[0].__name__, Alias.__value__.__origin__.__name__, Alias.__value__.__args__[0].__name__)",
        &["Alias T list T"],
    );
    assert_output("type = \"soft\"\nprint(type)", &["soft"]);
    assert_output(
        "def f():\n    type Local = int\n    return Local.__name__\nprint(f())",
        &["Local"],
    );
    assert_output(
        "class C:\n    type Local = int\nprint(C.Local.__name__)",
        &["Local"],
    );
    assert_output(
        "type type = int\nprint(type.__name__, type.__value__.__name__)",
        &["type int"],
    );
    assert_error(
        "type Alias int",
        "parse error: expected '=', found Identifier(\"int\")",
    );
}

