// Adapted from CPython
// Lib/test/test_syntax.py::SyntaxErrorTestCase::test_disallowed_type_param_names.
// The source is CPython-only today, so this remains a MiniPython parser subset
// instead of a system-Python differential test.
#[test]
fn cpython_disallowed_type_param_names_subset() {
    let message = "reserved name '__classdict__' cannot be used for type parameter";
    assert_error(
        "class A[__classdict__]: pass",
        &format!("parse error: {message}"),
    );
    assert_error(
        "def f[__classdict__](): pass",
        &format!("parse error: {message}"),
    );
    assert_error(
        "type T[__classdict__] = tuple[__classdict__]",
        &format!("parse error: {message}"),
    );

    for name in ["__class__", "__classcell__", "__classdictcell__"] {
        assert_parse_ok(&format!("class A:\n    class B[{name}]: pass"));
    }
}

// Adapted from CPython's `invalid_type_params` grammar rule. MiniPython rejects
// empty type parameter lists on functions, classes, and type aliases.
#[test]
fn cpython_invalid_type_params_subset() {
    assert_error(
        "def func[]():\n    pass",
        "parse error: Type parameter list cannot be empty",
    );
    assert_error(
        "class ClassA[]:\n    pass",
        "parse error: Type parameter list cannot be empty",
    );
    assert_error(
        "type Alias[] = int",
        "parse error: Type parameter list cannot be empty",
    );
}

// Adapted from CPython's `invalid_type_param` grammar rule. MiniPython rejects
// bounds and constraints on variadic TypeVarTuple and ParamSpec parameters.
#[test]
fn cpython_invalid_type_param_subset() {
    assert_error(
        "def func[*Ts: int]():\n    pass",
        "parse error: cannot use bound with TypeVarTuple",
    );
    assert_error(
        "class ClassA[*Ts: (int, str)]:\n    pass",
        "parse error: cannot use constraints with TypeVarTuple",
    );
    assert_error(
        "type Alias[**P: int] = int",
        "parse error: cannot use bound with ParamSpec",
    );
    assert_error(
        "def func[**P: (int, str)]():\n    pass",
        "parse error: cannot use constraints with ParamSpec",
    );
    assert_error(
        "def func[T: (x := 3)]():\n    pass",
        "parse error: named expression cannot be used within a TypeVar bound",
    );
    assert_error(
        "def func[T: ((x := 3), int)]():\n    pass",
        "parse error: named expression cannot be used within a TypeVar constraint",
    );
    assert_error(
        "def func[T = ((x := 3))]():\n    pass",
        "parse error: named expression cannot be used within a TypeVar default",
    );
    assert_error(
        "class ClassA[*Ts = (yield)]:\n    pass",
        "parse error: yield expression cannot be used within a TypeVarTuple default",
    );
    assert_error(
        "type Alias[**P = [(yield), int]] = int",
        "parse error: yield expression cannot be used within a ParamSpec default",
    );
}

// Adapted from CPython Lib/test/test_syntax.py "Invalid expressions in type
// scopes". Type aliases and generic definitions reject named expressions,
// yield expressions, and await expressions inside their type-only scopes.
#[test]
fn cpython_invalid_type_scope_expression_subset() {
    assert_error(
        "type Alias = (x := 3)",
        "parse error: named expression cannot be used within a type alias",
    );
    assert_error(
        "type Alias = (yield 3)",
        "parse error: yield expression cannot be used within a type alias",
    );
    assert_error(
        "type Alias = (await 3)",
        "parse error: await expression cannot be used within a type alias",
    );
    assert_error(
        "class ClassA[T]((x := 3)):\n    pass",
        "parse error: named expression cannot be used within the definition of a generic",
    );
    assert_error(
        "class ClassA[T]((yield 3)):\n    pass",
        "parse error: yield expression cannot be used within the definition of a generic",
    );
    assert_error(
        "class ClassA[T]((await 3)):\n    pass",
        "parse error: await expression cannot be used within the definition of a generic",
    );
}

// Adapted from CPython Lib/test/test_compile.py coverage for default values on
// plain, variadic, and ParamSpec type parameters.
#[test]
fn cpython_type_param_defaults_subset() {
    assert_output(
        "def foo[T = int, **P = float, *Ts = None]():\n    pass\nprint(foo.__type_params__[0].__default__.__name__, foo.__type_params__[1].__default__.__name__, foo.__type_params__[2].__default__)",
        &["int float None"],
    );
    assert_output(
        "class Foo[T = int, **P = float, *Ts = None]:\n    pass\nprint(Foo.__type_params__[0].__default__.__name__, Foo.__type_params__[1].__default__.__name__, Foo.__type_params__[2].__default__)",
        &["int float None"],
    );
    assert_output(
        "type Foo[T = int, **P = float, *Ts = None] = int\nprint(Foo.__type_params__[0].__default__.__name__, Foo.__type_params__[1].__default__.__name__, Foo.__type_params__[2].__default__)",
        &["int float None"],
    );
    assert_output(
        "type Foo[*Ts = *tuple[int, str]] = int\nprint(Foo.__type_params__[0].__default__.__origin__.__name__, Foo.__type_params__[0].__default__.__args__[0].__name__, Foo.__type_params__[0].__default__.__args__[1].__name__)",
        &["tuple int str"],
    );
    assert_output(
        "def foo[T = list[int], **P = dict[str, int]]():\n    pass\nprint(foo.__type_params__[0].__default__.__origin__.__name__, foo.__type_params__[0].__default__.__args__[0].__name__)\nprint(foo.__type_params__[1].__default__.__origin__.__name__, foo.__type_params__[1].__default__.__args__[0].__name__, foo.__type_params__[1].__default__.__args__[1].__name__)",
        &["list int", "dict str int"],
    );
}
